-- Schema for Domain: security | Business: Sports Entertainment | Version: v1_mvm
-- Generated on: 2026-05-09 04:52:11

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `sports_entertainment_ecm`.`security` COMMENT 'Event security and physical safety operations domain managing credentialing, access control zones, surveillance systems, crowd management protocols, emergency response plans, and law enforcement coordination for all Sports Entertainment venues and events.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`credential` (
    `credential_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for each security credential record. Primary key for the credential master table — SSOT for credential identity across all access control operations.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Credentials (facility access, locker room, sideline passes) are issued directly to athletes. Credentialing operations require linking each credential to the athlete it was issued to for access managem',
    `fixture_id` BIGINT COMMENT 'Reference to the specific event for which this credential is valid, if the credential is event-scoped rather than season- or venue-scoped. Null for standing/permanent credentials valid across all events at a venue.',
    `credential_fixture_id` BIGINT COMMENT 'Reference to the specific event for which this credential is valid, if the credential is event-scoped rather than season- or venue-scoped. Null for standing/permanent credentials valid across all events at a venue.',
    `eligibility_certification_id` BIGINT COMMENT 'Foreign key linking to compliance.eligibility_certification. Business justification: Credentials are issued based on approved eligibility certifications (TUEs, competition eligibility, broadcast access approvals). Accreditation workflows require the credential record to reference the ',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Credentials are issued to franchise staff, team personnel, and media. Franchise-level credential issuance audits, access control compliance reporting, and league credentialing reviews require linking ',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Rights-holder accreditation audit: credentials issued to broadcast media personnel must be validated against an active media rights deal. Compliance teams verify that credentialed journalists, camera ',
    `official_id` BIGINT COMMENT 'Foreign key linking to league.official. Business justification: Officials require security credentials for each game they officiate. Security issues and validates credentials for referees/umpires. Officiating management and pre-game credentialing workflows depend ',
    `reissued_from_credential_id` BIGINT COMMENT 'Self-referencing FK on credential (reissued_from_credential_id)',
    `season_id` BIGINT COMMENT 'Reference to the league season or tournament for which this credential is valid when multi_event_flag is True. Null for single-event credentials.',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Tournament-scoped credentials (World Cup press passes, Olympic accreditations) are valid across all fixtures in a tournament, not tied to a single fixture. credential.multi_event_flag signals this con',
    `venue_id` BIGINT COMMENT 'Reference to the venue at which this credential grants access. For multi-venue credentials, this references the primary or home venue; access to additional venues is managed via the access zone configuration.',
    `access_tier` STRING COMMENT 'Hierarchical access level granted by this credential, defining which physical zones the holder may enter. Values: field_level (playing surface and sidelines), locker_room (team areas), press_box (media and broadcast areas), general_operations (back-of-house operations), vip_suite (premium hospitality areas), restricted_zone (security command, broadcast infrastructure). [ENUM-REF-CANDIDATE: field_level|locker_room|press_box|general_operations|vip_suite|restricted_zone|medical_area|broadcast_compound — promote to reference product]. Valid values are `field_level|locker_room|press_box|general_operations|vip_suite|restricted_zone`',
    `access_zone_list` STRING COMMENT 'Comma-delimited list of specific zone codes within the venue that this credential authorizes entry to (e.g., Z01,Z04,Z07,Z12). Complements access_tier with granular zone-level control as configured in the access control system.',
    `accreditation_body` STRING COMMENT 'Name of the external governing body or league office that accredited this credential (e.g., FIFA Accreditation Centre, NFL League Office, IOC Media Accreditation). Relevant for media passes and law enforcement credentials requiring external validation.',
    `accreditation_reference` STRING COMMENT 'External reference number or accreditation ID assigned by the governing body or league office (e.g., FIFA accreditation number, IOC media pass number). Used for cross-referencing with external accreditation systems.',
    `background_check_date` DATE COMMENT 'Date on which the background check for this credential holder was completed and a determination was made. Used to assess recency of screening and trigger renewal workflows.',
    `background_check_status` STRING COMMENT 'Status of the background screening conducted on the credential holder prior to issuance. Classified as confidential business-sensitive data. Values: cleared (passed), pending (in progress), failed (did not pass), waived (exempted by policy), not_required (credential type exempt).. Valid values are `cleared|pending|failed|waived|not_required`',
    `barcode_value` DECIMAL(18,2) COMMENT 'Encoded barcode string (1D or 2D/QR) printed on or embedded in the credential, scanned at access control checkpoints. Classified as confidential as it is the operational key for physical access. Managed in alignment with Ticketmaster/AXS access control systems.',
    `biometric_linked` BOOLEAN COMMENT 'Indicates whether this credential has been linked to a biometric profile (e.g., fingerprint, facial recognition) for enhanced identity verification at high-security access points. True = biometric data is enrolled and active for this credential.',
    `biometric_type` STRING COMMENT 'Type of biometric modality enrolled for this credential when biometric_linked is True. Classified as restricted PII/biometric per GDPR Article 9 and CCPA. Values: fingerprint, facial_recognition, iris_scan, palm_vein, none.. Valid values are `fingerprint|facial_recognition|iris_scan|palm_vein|none`',
    `color_code` STRING COMMENT 'Hex color code representing the physical color of the credential lanyard or card stock, used for rapid visual identification of access tier by security staff at checkpoints (e.g., #FF0000 for red = restricted zone, #00FF00 for green = general operations).. Valid values are `^#[0-9A-Fa-f]{6}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this credential record was first created in the system. Supports audit trail, chain-of-custody tracking, and compliance reporting. Conforms to ISO 8601 format yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `credential_number` STRING COMMENT 'Externally visible, human-readable credential identifier printed on the physical badge or encoded in the digital pass (e.g., CRED-STAFF-000123). Used by security personnel and access control systems to reference a specific credential without exposing the internal surrogate key.. Valid values are `^CRED-[A-Z]{2,6}-[0-9]{6,10}$`',
    `credential_status` STRING COMMENT 'Current lifecycle state of the credential. active: valid and in use; suspended: temporarily deactivated (e.g., investigation); revoked: permanently cancelled; expired: past validity end date; pending_activation: issued but not yet activated; lost_stolen: reported missing and deactivated for security.. Valid values are `active|suspended|revoked|expired|pending_activation|lost_stolen`',
    `credential_type` STRING COMMENT 'Classification of the credential by the category of holder and access purpose. Drives access tier rules and issuance workflows. Values: staff_badge (venue/event staff), media_pass (accredited press/broadcast), vip_access_card (VIP guests and sponsors), contractor_id (third-party contractors), law_enforcement (police/security agencies), athlete_team (players, coaches, team officials).. Valid values are `staff_badge|media_pass|vip_access_card|contractor_id|law_enforcement|athlete_team`',
    `emergency_contact_name` STRING COMMENT 'Full name of the emergency contact person for the credential holder, used by venue medical and security staff in the event of an incident. Classified as restricted PII per GDPR and CCPA.',
    `emergency_contact_phone` STRING COMMENT 'Phone number of the emergency contact person for the credential holder. Classified as restricted PII per GDPR and CCPA. Used by venue medical and security staff in emergency situations.. Valid values are `^+?[0-9s-().]{7,20}$`',
    `escort_required` BOOLEAN COMMENT 'Indicates whether the credential holder must be accompanied by an authorized escort when accessing certain zones. True = escort is mandatory. Used for contractor and visitor credentials in high-security areas.',
    `holder_organization` STRING COMMENT 'Name of the organization, team, media outlet, agency, or employer that the credential holder represents (e.g., ESPN, Dallas Cowboys, ABC Security Services). Used for affiliation-based access grouping and sponsor/partner credential management.',
    `holder_role` STRING COMMENT 'Functional role or job title of the credential holder within the event or venue context (e.g., Head Coach, Camera Operator, Paramedic, Venue Director). Informs access tier assignment and is displayed on the physical credential.',
    `issued_date` DATE COMMENT 'Calendar date on which the credential was physically produced and issued to the holder. Distinct from valid_from (when access begins) — a credential may be issued days before it becomes active.',
    `issuing_authority` STRING COMMENT 'Name of the organizational unit or external body responsible for issuing and authorizing this credential (e.g., NFL Security Office, FIFA Accreditation Centre, Venue Security Manager). Establishes chain-of-custody accountability.',
    `issuing_authority_code` STRING COMMENT 'Standardized short code identifying the issuing authority (e.g., NFL_SEC, FIFA_ACC, VENUE_MGR). Used for system-level filtering and reporting across multi-league or multi-event deployments.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency represented by the credential holder (e.g., NYPD, FBI, US Secret Service). Populated only for credential_type = law_enforcement. Used for coordination with venue security command.',
    `law_enforcement_badge_number` STRING COMMENT 'Official badge or shield number of the law enforcement officer, used to verify identity against agency records. Classified as confidential. Populated only for credential_type = law_enforcement.',
    `multi_event_flag` BOOLEAN COMMENT 'Indicates whether this credential is valid across multiple events (e.g., a season-long staff badge or a tournament-wide media pass) rather than a single event. True = valid for multiple events within the validity period.',
    `photo_url` STRING COMMENT 'Secure URL pointing to the credential holders photograph stored in the Digital Asset Management (DAM) system, used for visual identity verification by security personnel. Classified as restricted biometric PII per GDPR Article 9.',
    `print_template_code` STRING COMMENT 'Code referencing the physical credential print template used for this credential type (e.g., TMPL-MEDIA-2024, TMPL-STAFF-VIP). Determines layout, branding, and security features printed on the badge.',
    `revocation_date` DATE COMMENT 'Date on which the credential was revoked or suspended. Populated only when credential_status is revoked, suspended, or lost_stolen. Part of the chain-of-custody audit trail.',
    `revocation_reason` STRING COMMENT 'Reason code explaining why the credential was revoked or suspended. Supports security incident analysis and compliance reporting. Values: lost, stolen, employment_terminated, event_concluded, policy_violation, voluntary_surrender, duplicate_issued. [ENUM-REF-CANDIDATE: lost|stolen|employment_terminated|event_concluded|policy_violation|voluntary_surrender|duplicate_issued — 7 candidates stripped; promote to reference product]',
    `rfid_tag_code` STRING COMMENT 'Unique identifier of the RFID chip embedded in the credential card or wristband, used for contactless access control scanning. Classified as confidential as it is a physical access key. Null if the credential does not use RFID technology.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this credential record originated (e.g., TICKETMASTER_AXS for access control credentials, ARCHTICS for venue-managed credentials, MANUAL_ENTRY for credentials issued outside automated systems). Supports data lineage in the Databricks Silver Layer.. Valid values are `TICKETMASTER_AXS|ARCHTICS|SALESFORCE_CRM|SAP_S4HANA|MANUAL_ENTRY`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this credential record. Used for change tracking, audit trail, and incremental data pipeline processing in the Databricks Silver Layer.',
    `valid_until` DATE COMMENT 'Date on which the credential expires and access is automatically revoked. For event credentials, typically the day after the event concludes. For season credentials, the last day of the season. Null indicates an open-ended standing credential subject to manual review.',
    `vehicle_access_flag` BOOLEAN COMMENT 'Indicates whether this credential also grants vehicle access to restricted parking or loading dock areas at the venue. True = vehicle access is authorized in addition to pedestrian access.',
    `vehicle_plate_number` STRING COMMENT 'License plate number of the vehicle authorized for venue access under this credential when vehicle_access_flag is True. Classified as confidential. Null if vehicle access is not granted.',
    `valid_from` DATE COMMENT 'Date from which the credential becomes active and grants access. For event credentials, typically the event setup/load-in date. For season credentials, the first day of the season.',
    CONSTRAINT pk_credential PRIMARY KEY(`credential_id`)
) COMMENT 'Master record for all security credentials issued to personnel operating at Sports Entertainment venues and events — staff badges, media passes, VIP access cards, contractor IDs, law enforcement credentials, and athlete/team credentials. Captures credential type, holder identity reference, issuing authority, validity period, access tier, biometric linkage flag, barcode/RFID identifier, revocation status, and chain-of-custody audit fields. SSOT for credential identity across all access control operations.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`access_zone` (
    `access_zone_id` BIGINT COMMENT 'Unique surrogate identifier for each physical access control zone record within the Sports Entertainment security master catalog.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Each access zone (field-level, media, VIP, concourse) has dedicated staffing and operational costs tracked to a cost center. Venue finance teams budget and report security labor and maintenance costs ',
    `facility_id` BIGINT COMMENT 'FK to venue.facility.facility_id — Security zones must be linked to their physical venue facility for operational deployment planning and zone-to-venue mapping.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Franchise-controlled zones (locker rooms, team benches, owner suites) are access zones tied to a specific franchise. Security staff validate credentials against franchise-specific zone ownership. Fran',
    `parent_access_zone_id` BIGINT COMMENT 'Self-referencing FK on access_zone (parent_access_zone_id)',
    `venue_id` BIGINT COMMENT 'Reference to the parent venue where this access zone is physically located. Used to scope zone records to a specific Sports Entertainment facility.',
    `access_close_time` TIMESTAMP COMMENT 'Standard time of day (HH:MM, 24-hour format) at which access to this zone closes relative to event day operations (e.g., 23:59 for post-event lockdown). Used for access control system scheduling and security staffing deployment.',
    `access_control_system` STRING COMMENT 'Name or type of the electronic access control system managing entry/exit to this zone (e.g., Ticketmaster/AXS turnstile, Lenel, C-Cure, Genetec, Honeywell, manual staffed checkpoint, or none). Determines integration points for real-time access event logging. [ENUM-REF-CANDIDATE: ticketmaster_axs|lenel|ccure|genetec|honeywell|manual|none — 7 candidates stripped; promote to reference product]',
    `access_open_time` TIMESTAMP COMMENT 'Standard time of day (HH:MM, 24-hour format) at which access to this zone opens relative to event day operations (e.g., 06:00 for early crew access). Used for access control system scheduling and security staffing deployment.',
    `ada_accessible_flag` BOOLEAN COMMENT 'Indicates whether the access zone meets ADA accessibility requirements including wheelchair access, accessible entry/exit points, and compliant pathways (True = ADA compliant, False = not compliant or not assessed). Required for ADA regulatory reporting.',
    `adjacent_zone_codes` STRING COMMENT 'Comma-separated list of zone_codes for physically adjacent access zones sharing a boundary or transition point with this zone. Used for crowd flow modeling, spillover risk assessment, and emergency egress path analysis. Note: a dedicated zone_adjacency junction product should be used for full relational modeling.',
    `alcohol_permitted_flag` BOOLEAN COMMENT 'Indicates whether alcohol consumption and/or service is permitted within this zone (True = permitted, False = not permitted). Used for concession operations planning, liquor licensing compliance, and fan experience management.',
    `broadcast_zone_flag` BOOLEAN COMMENT 'Indicates whether this zone is designated as a broadcast or media production area (True = broadcast zone, False = non-broadcast). Triggers media credential requirements and coordination with broadcast operations teams and OB (Outside Broadcast) units.',
    `camera_count` STRING COMMENT 'Number of surveillance cameras installed and actively monitoring the access zone. Used for security audit compliance, coverage gap analysis, and incident response planning.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this access zone record was first created in the system. Used for audit trail, data lineage, and compliance with SOX and GDPR record-keeping requirements.',
    `credential_type_required` STRING COMMENT 'Type of credential required for access to this zone (e.g., event_ticket, staff_badge, media_credential, vip_wristband, law_enforcement_id, biometric, all_access_pass). Drives credentialing issuance rules in Ticketmaster/AXS and physical security systems. [ENUM-REF-CANDIDATE: event_ticket|staff_badge|media_credential|vip_wristband|law_enforcement_id|biometric|all_access_pass|none — promote to reference product]',
    `effective_from_date` DATE COMMENT 'Date from which this access zone definition became operationally active and enforceable. Used for historical zone configuration tracking, audit trails, and compliance with venue certification requirements.',
    `effective_until_date` DATE COMMENT 'Date on which this access zone definition expires or is superseded. Null indicates the zone definition is currently open-ended and active. Used for zone lifecycle management and historical configuration auditing.',
    `emergency_assembly_point_flag` BOOLEAN COMMENT 'Indicates whether this zone serves as a designated emergency assembly or muster point during evacuation scenarios (True = designated assembly point, False = not designated). Used in emergency response plans and evacuation drills.',
    `entry_point_count` STRING COMMENT 'Number of physical entry points (gates, turnstiles, doors, checkpoints) providing access into this zone. Used for crowd flow throughput modeling, staffing calculations, and emergency egress planning.',
    `evacuation_route_code` STRING COMMENT 'Code identifying the primary designated evacuation route assigned to this zone in the venue emergency response plan. Used by security command center and first responders during emergency scenarios.. Valid values are `^[A-Z0-9_-]{1,15}$`',
    `exit_point_count` STRING COMMENT 'Number of physical exit points from this zone. Used for emergency evacuation planning, egress compliance with fire safety codes, and crowd flow modeling.',
    `floor_area_sqm` DECIMAL(18,2) COMMENT 'Physical floor area of the access zone measured in square metres. Used to calculate occupancy density ratios, crowd flow modeling, and compliance with safety regulations requiring minimum space per person.',
    `hvac_zone_reference` STRING COMMENT 'Reference code linking this access zone to the corresponding HVAC zone in the Building Management System (BMS). Used for environmental control coordination during events and emergency ventilation management.',
    `last_safety_inspection_date` DATE COMMENT 'Date of the most recent physical safety inspection conducted for this access zone by internal safety officers or external regulatory inspectors. Used for OSHA compliance tracking and venue certification renewals.',
    `law_enforcement_required_flag` BOOLEAN COMMENT 'Indicates whether sworn law enforcement officers are required to be stationed at or within this zone during events (True = required, False = not required). Used for event security planning, law enforcement coordination, and regulatory compliance.',
    `level_number` STRING COMMENT 'Numeric floor or level within the venue where the zone is located (e.g., 0 = ground/field level, 1 = concourse level, 2 = upper deck, -1 = sub-ground). Used for wayfinding, evacuation routing, and zone adjacency mapping.',
    `map_coordinates` STRING COMMENT 'Geographic or venue-relative coordinate string (e.g., GeoJSON polygon or venue grid reference) defining the physical boundary of the zone on the venue floor plan. Used for digital venue mapping, crowd flow modeling, and real-time occupancy visualization.',
    `max_occupancy` STRING COMMENT 'Maximum number of persons permitted within the zone simultaneously as defined by fire safety codes, venue engineering assessments, and regulatory approvals. Used for crowd flow modeling, real-time occupancy monitoring, and ADA compliance reporting.',
    `min_security_staff_count` STRING COMMENT 'Minimum number of security personnel required to be deployed in this zone during an active event. Used for event staffing plans, security contractor scheduling, and compliance with venue safety regulations.',
    `next_safety_inspection_date` DATE COMMENT 'Scheduled date for the next mandatory safety inspection of this access zone. Used for compliance calendar management and proactive safety governance.',
    `notes` STRING COMMENT 'Free-text field for operational notes, special instructions, or temporary conditions relevant to this access zone (e.g., Temporary barrier installed for renovation, Law enforcement post required for playoff events). Used by security operations staff.',
    `re_entry_permitted_flag` BOOLEAN COMMENT 'Indicates whether credential holders who have exited this zone are permitted to re-enter during the same event (True = re-entry allowed, False = no re-entry). Drives access control system configuration in Ticketmaster/AXS.',
    `screening_protocol` STRING COMMENT 'Security screening method applied at entry points to this zone: none, visual_check, metal_detector, magnetometer, pat_down, full_search, or biometric_scan. Determines staffing requirements and equipment deployment for event security operations. [ENUM-REF-CANDIDATE: none|visual_check|metal_detector|magnetometer|pat_down|full_search|biometric_scan — 7 candidates stripped; promote to reference product]',
    `section_reference` STRING COMMENT 'Venue section or block designation within which the access zone falls (e.g., North Stand, Section 112, East Wing). Aligns with Archtics seating inventory and venue map coordinates for operational cross-referencing.',
    `smoking_permitted_flag` BOOLEAN COMMENT 'Indicates whether smoking is permitted within this zone (True = permitted, False = not permitted). Used for venue policy enforcement, health and safety compliance, and fan experience communications.',
    `surveillance_coverage_flag` BOOLEAN COMMENT 'Indicates whether the access zone is covered by CCTV or other surveillance systems (True = covered, False = not covered). Critical for security planning, incident investigation, and compliance with venue safety regulations.',
    `time_restricted_flag` BOOLEAN COMMENT 'Indicates whether access to this zone is restricted to specific time windows during an event (True = time-restricted, False = open throughout event). When True, access_open_time and access_close_time define the permitted window.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this access zone record was most recently modified. Used for change tracking, audit trail, and data freshness monitoring in the Databricks Silver Layer.',
    `vip_flag` BOOLEAN COMMENT 'Indicates whether this zone is designated as a VIP hospitality or premium access area (True = VIP zone, False = standard zone). Drives premium credentialing rules, enhanced security protocols, and sponsor/partner access management.',
    `zone_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the access zone within a venue (e.g., FIELD-01, PRESS-BOX-A, VIP-SUITE-N). Used on credentials, wristbands, and access control hardware programming.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `zone_color_code` STRING COMMENT 'Hexadecimal color code used to visually represent this zone on venue maps, security dashboards, and credentialing systems (e.g., #FF0000 for red restricted zones, #00FF00 for public green zones). Standardizes visual communication across security operations.. Valid values are `^#[0-9A-Fa-f]{6}$`',
    `zone_description` STRING COMMENT 'Free-text narrative description of the access zone including its physical characteristics, operational purpose, notable features, and any special access conditions not captured in structured fields. Used for security briefings and operational documentation.',
    `zone_name` STRING COMMENT 'Human-readable descriptive name of the access zone (e.g., Field Level / Pitch Side, Home Team Locker Room, Broadcast Compound, VIP Hospitality Suite North). Used in operational reports and credentialing systems.',
    `zone_status` STRING COMMENT 'Current operational lifecycle status of the access zone: active (in normal use), inactive (temporarily disabled), under_maintenance (physical works in progress), decommissioned (permanently retired), temporary (event-specific pop-up zone). Drives whether the zone is enforced in access control systems.. Valid values are `active|inactive|under_maintenance|decommissioned|temporary`',
    `zone_tier` STRING COMMENT 'Security classification tier of the zone defining the baseline access control level: public (general admission concourse), restricted (credentialed staff/media), secured (law enforcement / command), sterile (field/pitch/locker room — highest protection). Drives credentialing rules and screening protocols.. Valid values are `public|restricted|secured|sterile`',
    `zone_type` STRING COMMENT 'Functional category of the zone describing its operational purpose: field_pitch, locker_room, press_box, broadcast_compound, vip_hospitality, back_of_house, command_center, parking_compound, public_concourse, medical, production_truck_bay, merchandise_storage. [ENUM-REF-CANDIDATE: field_pitch|locker_room|press_box|broadcast_compound|vip_hospitality|back_of_house|command_center|parking_compound|public_concourse|medical|production_truck_bay|merchandise_storage — promote to reference product]',
    CONSTRAINT pk_access_zone PRIMARY KEY(`access_zone_id`)
) COMMENT 'Master catalog of all defined physical access control zones within Sports Entertainment venues — field/pitch level, locker rooms, press box, broadcast compound, VIP hospitality, back-of-house, command center, parking compounds, and public concourse zones. Captures zone code, zone name, venue reference, zone tier (public/restricted/secured/sterile), maximum occupancy, surveillance coverage flag, and zone adjacency metadata used for crowd flow modeling.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`credential_assignment` (
    `credential_assignment_id` BIGINT COMMENT 'Unique system-generated identifier for each credential assignment record. Primary key for the credential_assignment data product in the security domain.',
    `access_zone_id` BIGINT COMMENT 'Reference to the primary access control zone or area that this credential assignment grants entry to. Supports zone-based access management within the venue.',
    `activation_id` BIGINT COMMENT 'Foreign key linking to sponsorship.sponsorship_activation. Business justification: Sponsor staff, brand reps, and VIP guests require credential assignments tied to specific activations (e.g., Pepsi halftime zone, Nike fan experience). Security ops issue credentials per activation to',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Credential assignments are made to athletes for specific events and venues. Linking assignments to athlete profiles enables access management reporting, credential audit trails, and enforcement of sus',
    `credential_id` BIGINT COMMENT 'Reference to the specific credential (badge, pass, wristband, RFID card) being assigned to the holder. Links to the credential master record.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Credential assignments for franchise staff and media require franchise attribution for franchise-level access control audits, league credentialing compliance reporting, and franchise-specific access z',
    `fan_profile_id` BIGINT COMMENT 'Foreign key linking to fan.fan_profile. Business justification: Credential assignments for fan holders (season ticket, VIP, fan club) must reference the fan profile to enable event-day access verification, ban enforcement checks, and post-event attendance reportin',
    `league_schedule_id` BIGINT COMMENT 'Foreign key linking to league.league_schedule. Business justification: Game-day credential assignments for media, officials, and team staff are organized around the specific scheduled game. Pre-game credentialing workflows and post-game access audits require linking assi',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped credential assignments support league-wide access control audits, franchise credential compliance reviews, and CBA-mandated media/staff access protocol reporting across the full season.',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Media rights accreditation workflow: credential assignments for broadcast personnel are governed by the media rights deal that entitles the rights holder to field/press-box access. Rights compliance a',
    `fixture_id` BIGINT COMMENT 'Reference to the specific sports or entertainment event for which this credential assignment is valid. Null if the assignment is venue-wide or period-based rather than event-specific.',
    `superseded_credential_assignment_id` BIGINT COMMENT 'Self-referencing FK on credential_assignment (superseded_credential_assignment_id)',
    `venue_id` BIGINT COMMENT 'Reference to the venue or facility where this credential assignment is valid. Supports venue-wide credentialing independent of a specific event.',
    `access_level` STRING COMMENT 'Categorical access tier granted by this credential assignment, defining the scope of areas the holder may enter within the venue. Drives access control system enforcement at entry points. [ENUM-REF-CANDIDATE: field|locker_room|press_box|backstage|general|restricted|all_access|vip|production — promote to reference product]',
    `assignment_date` DATE COMMENT 'Calendar date on which the credential was formally assigned to the holder by the credentialing authority. Represents the principal business event date for this transaction.',
    `assignment_number` STRING COMMENT 'Externally-known human-readable business identifier for the credential assignment, used in credentialing workflows, printed on assignment receipts, and referenced in post-event reconciliation reports. Format: CA-{YYYY}-{NNNNNN}.. Valid values are `^CA-[0-9]{4}-[0-9]{6}$`',
    `assignment_status` STRING COMMENT 'Current lifecycle state of the credential assignment. Drives operational workflows including pickup confirmation, access control enforcement, and post-event reconciliation. [ENUM-REF-CANDIDATE: pending|issued|active|suspended|revoked|returned|expired|lost|stolen — promote to reference product]',
    `assignment_timestamp` TIMESTAMP COMMENT 'Precise date and time at which the credential assignment was created in the system, capturing the exact moment of authorization. Used for audit trail and security incident investigation.',
    `background_check_date` DATE COMMENT 'Date on which the background check for the credential holder was completed or last updated. Used to determine if a background check is current and valid for the assignment period.',
    `background_check_status` STRING COMMENT 'Status of the background screening conducted on the credential holder prior to credential issuance. Cleared status is required for access to restricted zones such as locker rooms and field areas.. Valid values are `pending|cleared|failed|waived|not_required`',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this credential assignment record was first created in the data platform. Used for audit trail, data lineage, and compliance reporting.',
    `credential_scope` STRING COMMENT 'Defines the temporal and event scope of the credential assignment — whether it is valid for a single event, multiple events, an entire season, or the venue broadly. Drives validity period enforcement and renewal workflows.. Valid values are `single_event|multi_event|season|venue_wide|tournament`',
    `credential_type` STRING COMMENT 'Physical or digital form factor of the credential being assigned. Determines issuance workflow, pickup process, and return reconciliation procedures.. Valid values are `badge|wristband|rfid_card|lanyard_pass|vehicle_pass|digital_pass`',
    `escort_required` BOOLEAN COMMENT 'Indicates whether the credential holder must be accompanied by an authorized escort when accessing credentialed areas. True when escort is mandatory; False when holder may access independently.',
    `event_day_number` STRING COMMENT 'For multi-day events (tournaments, festivals, conventions), the specific day number within the event for which this credential is valid. Null for single-day events or season-wide credentials.',
    `holder_id_number` STRING COMMENT 'Government-issued or organizational identification number (e.g., employee ID, press pass number, law enforcement badge number) used to verify the identity of the credential holder at time of issuance.',
    `holder_organization` STRING COMMENT 'Name of the organization, employer, or entity that the credential holder represents (e.g., ESPN, ABC Security Services, NFL Players Association). Used for credentialing workflow routing and sponsor/media tracking.',
    `holder_photo_url` STRING COMMENT 'Secure URL reference to the credential holders photo image stored in the Digital Asset Management (DAM) system. Used for visual identity verification at access control points. Subject to biometric data protection regulations.',
    `holder_type` STRING COMMENT 'Classification of the individual receiving the credential, defining their role and relationship to the event or venue. Drives access zone eligibility and credentialing workflow routing. [ENUM-REF-CANDIDATE: staff|media|contractor|law_enforcement|athlete|sponsor|vip|volunteer|official|vendor — promote to reference product]. Valid values are `staff|media|contractor|law_enforcement|athlete|sponsor`',
    `issued_timestamp` TIMESTAMP COMMENT 'Date and time at which the physical or digital credential was formally issued and activated in the access control system. Distinct from assignment_timestamp (when the record was created) and pickup_timestamp (when the holder collected it).',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this credential assignment record was most recently modified. Used for change tracking, audit trail, and incremental data pipeline processing.',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency represented by the credential holder, applicable when holder_type is law_enforcement (e.g., NYPD, FBI, US Secret Service). Used for law enforcement coordination and post-event reporting.',
    `meal_entitlement` BOOLEAN COMMENT 'Indicates whether the credential assignment includes meal or catering entitlement in designated hospitality areas (e.g., press dining, staff cafeteria). Used for catering planning and cost allocation.',
    `multi_zone_access` BOOLEAN COMMENT 'Indicates whether this credential assignment grants access to multiple zones beyond the primary access zone. True when the holder is authorized for more than one zone; False for single-zone access.',
    `parking_zone` STRING COMMENT 'Designated parking zone or lot assigned to the credential holder when vehicle access is granted (e.g., Lot A - Media, Field Level - Broadcast, VIP Garage). Null when vehicle_access is False.',
    `pickup_confirmed` BOOLEAN COMMENT 'Indicates whether the credential holder has physically collected the credential from the credentialing desk. True when pickup has been confirmed; False when credential is still awaiting collection.',
    `pickup_location` STRING COMMENT 'Name or designation of the credentialing desk, gate, or location where the credential was or is to be collected by the holder (e.g., Media Gate North, VIP Credentialing Desk Level 2).',
    `pickup_timestamp` TIMESTAMP COMMENT 'Date and time at which the credential holder physically collected the credential from the credentialing desk. Null if credential has not yet been picked up.',
    `return_confirmed` BOOLEAN COMMENT 'Indicates whether the credential has been returned to the credentialing authority after the event or assignment period. True when return is confirmed; False when credential is still outstanding. Critical for post-event reconciliation.',
    `return_timestamp` TIMESTAMP COMMENT 'Date and time at which the credential was returned to the credentialing authority. Null if credential has not yet been returned. Used in post-event reconciliation to identify unreturned credentials.',
    `revocation_reason` STRING COMMENT 'Free-text description of the reason a credential assignment was revoked or suspended before its natural expiry (e.g., Security incident, Holder no longer authorized, Lost credential reported). Null when assignment has not been revoked.',
    `revocation_timestamp` TIMESTAMP COMMENT 'Date and time at which the credential assignment was revoked or suspended. Null when assignment has not been revoked. Used for security incident investigation and access control audit trails.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this credential assignment record originated (e.g., Ticketmaster/AXS access control, Archtics venue seating and inventory, manual credentialing desk entry). Supports data lineage and reconciliation.. Valid values are `ticketmaster_axs|archtics|manual|salesforce_crm|sap_s4hana`',
    `special_access_notes` STRING COMMENT 'Free-text field capturing any special access permissions, restrictions, or annotations associated with this credential assignment (e.g., Authorized for post-game press conference only, Escort required at all times). Supports non-standard credentialing scenarios.',
    `valid_until` TIMESTAMP COMMENT 'Date and time at which the credential assignment expires and access is no longer granted. Null for open-ended assignments. Critical for post-event reconciliation and access revocation.',
    `vehicle_access` BOOLEAN COMMENT 'Indicates whether this credential assignment includes authorization for vehicle access to restricted venue areas such as loading docks, field-level parking, or broadcast compound. True when vehicle access is granted.',
    `valid_from` TIMESTAMP COMMENT 'Date and time from which the credential assignment becomes active and grants access. Supports time-bounded credentialing for multi-day events or seasonal venue access.',
    CONSTRAINT pk_credential_assignment PRIMARY KEY(`credential_assignment_id`)
) COMMENT 'Transactional record linking a specific credential to an authorized holder for a defined event or period. Captures credential ID, holder type (staff, media, contractor, law enforcement, athlete, sponsor), event or venue scope, assignment date, assigned-by officer, pickup confirmation, return confirmation, and any special access annotations. Enables per-event credentialing workflows and post-event reconciliation.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`access_event` (
    `access_event_id` BIGINT COMMENT 'Unique surrogate identifier for each physical access control scan event record in the Silver layer lakehouse. Primary key for this table.',
    `access_zone_id` BIGINT COMMENT 'Reference to the access control zone (e.g., field level, media area, backstage, VIP suite corridor) that the credential holder attempted to enter.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Access events log athlete entry/exit at facilities. WADA whereabouts compliance requires documented facility access records for athletes in the registered testing pool. Security audits and incident in',
    `calendar_id` BIGINT COMMENT 'Reference to the scheduled sports or entertainment event during which this access scan occurred. Links the access record to the event context for occupancy and security reporting.',
    `credential_assignment_id` BIGINT COMMENT 'Foreign key linking to security.credential_assignment. Business justification: An access event validates a credential that was formally assigned to a holder via credential_assignment. While access_event already has credential_id, the credential_assignment record captures the spe',
    `credential_id` BIGINT COMMENT 'Reference to the credential (badge, card, biometric token, or digital pass) that was presented at the reader. Distinct from a fan ticket — covers staff, media, VIP, and operational credentials.',
    `fixture_id` BIGINT COMMENT 'Reference to the scheduled sports or entertainment event during which this access scan occurred. Links the access record to the event context for occupancy and security reporting.',
    `override_of_access_event_id` BIGINT COMMENT 'Self-referencing FK on access_event (override_of_access_event_id)',
    `primary_access_fixture_id` BIGINT COMMENT 'FK to event.fixture.fixture_id — Event-correlated access control — security operations must correlate access scans to specific events for crowd management, capacity monitoring, and incident investigation.',
    `screening_checkpoint_id` BIGINT COMMENT 'Foreign key linking to security.screening_checkpoint. Business justification: An access control scan event (access_event) occurs at a physical location — often a screening checkpoint. The access_event table currently stores checkpoint_name as a denormalized STRING. Adding scree',
    `security_incident_id` BIGINT COMMENT 'Reference to a security incident record if this access event triggered or was associated with a security incident. Null when no incident was raised. Supports post-event forensic review and incident management workflows.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the access event occurred. Used to associate the scan event with a specific Sports Entertainment facility.',
    `access_direction` STRING COMMENT 'Direction of movement at the checkpoint: entry = entering the zone or venue, exit = leaving the zone or venue, internal = movement between internal zones. Used for real-time occupancy tracking and crowd flow analysis.. Valid values are `entry|exit|internal`',
    `ada_accommodation_flag` BOOLEAN COMMENT 'Indicates whether the credential holder required an ADA (Americans with Disabilities Act) accommodation at this access point (e.g., accessible gate routing). True = ADA accommodation applied; False = standard access.',
    `anti_passback_zone` STRING COMMENT 'Identifier of the anti-passback zone group assigned to this checkpoint. Anti-passback rules prevent a credential from being used to enter a zone it has not exited. Used for tailgating detection and occupancy integrity.',
    `biometric_verified_flag` BOOLEAN COMMENT 'Indicates whether biometric verification (e.g., facial recognition, fingerprint) was used as part of the credential authentication for this scan event. True = biometric match confirmed; False = biometric not used or not matched.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this access event record was first written to the Silver layer lakehouse. Distinct from scan_timestamp (the real-world event time). Used for data pipeline audit trails and SLA monitoring.',
    `credential_holder_category` STRING COMMENT 'Broad category of the person holding the credential. Distinct from credential_type (which describes the credential itself); this describes the persons role. Used for access pattern analytics and compliance reporting. [ENUM-REF-CANDIDATE: athlete|staff|media|vip|vendor|law_enforcement|official — 7 candidates stripped; promote to reference product]',
    `credential_token` STRING COMMENT 'Tokenized or masked representation of the physical credential identifier (e.g., RFID card number, barcode, NFC token) as presented to the reader. Stored in tokenized form to comply with PCI-DSS and GDPR. Not the raw credential number.',
    `credential_type` STRING COMMENT 'Classification of the credential presented at the reader. Distinguishes between staff, media, VIP, vendor, law enforcement, athlete, and digital mobile credentials. [ENUM-REF-CANDIDATE: staff_badge|media_pass|vip_credential|vendor_pass|law_enforcement|athlete_credential|digital_mobile — promote to reference product]',
    `data_retention_expiry_date` DATE COMMENT 'Date on which this access event record is scheduled for deletion or anonymization per applicable data retention policies (GDPR, CCPA). Supports automated data lifecycle management in the lakehouse.',
    `denial_reason_code` STRING COMMENT 'Standardized code indicating why access was denied or flagged. Null when scan_result is granted or override_granted. [ENUM-REF-CANDIDATE: INVALID_CREDENTIAL|EXPIRED_CREDENTIAL|ZONE_NOT_AUTHORIZED|BLACKLISTED|DUPLICATE_SCAN|CAPACITY_EXCEEDED|SYSTEM_ERROR — promote to reference product]',
    `duplicate_scan_flag` BOOLEAN COMMENT 'Indicates whether this scan event was detected as a duplicate presentation of the same credential within a short time window (anti-passback detection). True = duplicate detected; False = unique scan.',
    `emergency_evacuation_flag` BOOLEAN COMMENT 'Indicates whether this scan event occurred during an active emergency evacuation protocol. True = evacuation mode active at time of scan; False = normal operations. Critical for post-incident headcount reconciliation.',
    `event_phase` STRING COMMENT 'Operational phase of the event at the time of the scan. Used to segment access patterns by event lifecycle stage for crowd management analytics and post-event review.. Valid values are `pre_event|doors_open|in_progress|halftime|post_event|emergency`',
    `gdpr_data_subject_flag` BOOLEAN COMMENT 'Indicates whether the credential holder associated with this scan event is a data subject under GDPR jurisdiction (e.g., EU resident). True = GDPR data subject protections apply; False = not subject to GDPR. Drives data retention and erasure workflows.',
    `law_enforcement_notified_flag` BOOLEAN COMMENT 'Indicates whether law enforcement was notified as a result of this access event (e.g., blacklisted credential, flagged individual). True = law enforcement notification triggered; False = no notification.',
    `network_zone` STRING COMMENT 'Network segment or VLAN identifier of the reader device that processed this scan. Used for cybersecurity segmentation audits and forensic network analysis in the event of a security breach.',
    `occupancy_count_at_scan` STRING COMMENT 'Snapshot of the current occupancy count for the zone at the moment this scan event was processed. Captured at scan time to support real-time occupancy tracking and capacity compliance reporting.',
    `officer_override_flag` BOOLEAN COMMENT 'Indicates whether a security officer manually overrode the systems access decision for this event. True = officer override applied; False = system decision was final. Critical for post-event forensic review and accountability audits.',
    `override_justification` STRING COMMENT 'Free-text or coded reason provided by the officer when performing a manual override. Required when officer_override_flag is True. Supports accountability and compliance audit trails.',
    `reader_device_code` BIGINT COMMENT 'Reference to the physical access control reader or scanner device that captured this scan event. Used for device-level diagnostics, tamper detection, and post-event forensic review.',
    `reader_firmware_version` STRING COMMENT 'Firmware version of the access control reader device at the time of the scan. Captured for forensic integrity, device audit trails, and vulnerability management compliance.',
    `reader_location_code` STRING COMMENT 'Alphanumeric code identifying the physical location of the reader device within the venue (e.g., NE-G1-R04). Supports device-level forensic analysis and maintenance tracking.',
    `scan_duration_ms` STRING COMMENT 'Time in milliseconds taken for the reader to process the credential and return a result. Used for throughput analysis, reader performance monitoring, and identifying bottlenecks at high-traffic checkpoints.',
    `scan_result` STRING COMMENT 'Outcome of the credential scan at the access point. granted = access permitted; denied = access refused; flagged = access held for secondary review; override_granted = officer manually permitted entry; timeout = reader did not receive a valid response. Core field for real-time occupancy tracking and compliance audit trails.. Valid values are `granted|denied|flagged|override_granted|timeout`',
    `scan_timestamp` TIMESTAMP COMMENT 'Precise date and time (with timezone offset) when the credential was presented to the reader. The principal real-world event time for this access event. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `source_event_reference` STRING COMMENT 'The original event transaction ID or record key from the source access control system (e.g., Ticketmaster/AXS transaction ID). Enables traceability back to the operational system of record for audit and reconciliation.',
    `source_system_code` STRING COMMENT 'Code identifying the access control system that originated this scan event record (e.g., AXS, Ticketmaster, Lenel, C-Cure, Genetec). Supports multi-system venue environments and data lineage tracking in the Silver layer.. Valid values are `AXS|TICKETMASTER|LENEL|CCURE|GENETEC|CUSTOM`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this access event record was last modified in the Silver layer (e.g., enrichment, correction, incident linkage). Supports data lineage and audit trail requirements.',
    `watchlist_match_flag` BOOLEAN COMMENT 'Indicates whether the credential or credential holder matched an entry on a security watchlist at the time of the scan. True = watchlist match detected; False = no match. Triggers escalation workflows.',
    `zone_capacity` STRING COMMENT 'Maximum permitted occupancy for the zone at the time of the scan event, as configured in the access control system. Used alongside occupancy_count_at_scan to determine capacity compliance status.',
    `zone_level` STRING COMMENT 'Security classification level of the zone being accessed at the time of the scan. Captures the sensitivity of the zone for risk-tiered reporting and compliance. Values: public, restricted, highly_restricted, field_level, backstage.. Valid values are `public|restricted|highly_restricted|field_level|backstage`',
    CONSTRAINT pk_access_event PRIMARY KEY(`access_event_id`)
) COMMENT 'High-volume transactional record of every physical access control scan event at venue entry and internal zone checkpoints — credential presented, zone accessed, timestamp, scan result (granted/denied/flagged), reader device ID, officer override flag, and denial reason code. Feeds real-time occupancy tracking, post-event forensic review, and compliance audit trails. Distinct from ticketing.gate_scan which covers fan ticket entitlement scanning.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`screening_checkpoint` (
    `screening_checkpoint_id` BIGINT COMMENT 'Unique surrogate identifier for each physical security screening checkpoint record in the Sports Entertainment venue security master. Primary key for the screening_checkpoint data product.',
    `access_zone_id` BIGINT COMMENT 'Foreign key linking to security.access_zone. Business justification: A screening checkpoint controls physical entry into a specific access zone — it is the gateway to that zone. The existing access_zone_level (STRING) is a denormalized attribute describing the zone tie',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Screening checkpoint operations (staffing, equipment calibration, consumables) are budgeted and tracked per checkpoint in venue finance. Linking to cost_center enables per-gate cost reporting, staffin',
    `parent_screening_checkpoint_id` BIGINT COMMENT 'Self-referencing FK on screening_checkpoint (parent_screening_checkpoint_id)',
    `venue_id` BIGINT COMMENT 'Reference to the Sports Entertainment venue where this screening checkpoint is physically deployed. Links to the venue master record.',
    `activation_end_time` TIMESTAMP COMMENT 'Standard time of day (HH:MM, 24-hour format) at which this checkpoint ceases screening operations and is deactivated. Used for egress planning and post-event security stand-down scheduling.',
    `activation_schedule_type` STRING COMMENT 'Defines the operational activation pattern for this checkpoint — whether it is staffed only on event days, permanently active, activated seasonally, or deployed on-demand for high-security events. Drives resource planning and cost allocation.. Valid values are `event_day_only|permanent|seasonal|on_demand`',
    `activation_start_time` TIMESTAMP COMMENT 'Standard time of day (HH:MM, 24-hour format) at which this checkpoint is activated and begins screening operations relative to event start. Used for gate opening schedules and ingress management planning.',
    `ada_lane_count` STRING COMMENT 'Number of ADA (Americans with Disabilities Act) compliant accessible screening lanes available at this checkpoint. Distinct from the total lane count — used for ADA compliance reporting and accessibility planning.',
    `checkpoint_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the screening checkpoint, used in operational communications, staffing assignments, and incident reporting (e.g., GATE-A-MAG-01, VIP-BAG-03). Unique within a venue.. Valid values are `^[A-Z0-9]{2,20}$`',
    `checkpoint_name` STRING COMMENT 'Human-readable descriptive name for the screening checkpoint as displayed on operational maps, staff briefings, and incident reports (e.g., North Gate Magnetometer Lane 2, VIP Credentialing Desk East).',
    `checkpoint_status` STRING COMMENT 'Current operational lifecycle status of the screening checkpoint. Drives activation scheduling, staffing allocation, and security coverage gap analysis.. Valid values are `active|inactive|standby|decommissioned|under_maintenance`',
    `checkpoint_type` STRING COMMENT 'Classification of the physical security screening checkpoint by its primary function and method of screening. Drives staffing requirements, equipment deployment, and throughput planning. [ENUM-REF-CANDIDATE: magnetometer_lane|bag_check_station|pat_down_area|vehicle_inspection|credentialing_desk|explosive_trace_detection — promote to reference product if additional types are added]. Valid values are `magnetometer_lane|bag_check_station|pat_down_area|vehicle_inspection|credentialing_desk|explosive_trace_detection`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this screening checkpoint master record was first created in the system. Supports data lineage, audit trail requirements, and Silver layer ingestion tracking.',
    `credential_type_accepted` STRING COMMENT 'Type(s) of credentials or access passes accepted at this checkpoint for entry authorization (e.g., event_ticket, media_credential, staff_badge, law_enforcement_id). Drives access control configuration in Ticketmaster/AXS. [ENUM-REF-CANDIDATE: event_ticket|media_credential|staff_badge|law_enforcement_id|vip_pass|vendor_pass|athlete_credential — promote to reference product]',
    `effective_from_date` DATE COMMENT 'Date from which this screening checkpoint record is operationally valid and available for deployment. Supports checkpoint lifecycle management and historical security configuration auditing.',
    `effective_until_date` DATE COMMENT 'Date after which this screening checkpoint record is no longer operationally valid (e.g., due to decommissioning, venue renovation, or permanent closure). Nullable for indefinitely active checkpoints.',
    `emergency_response_zone` STRING COMMENT 'Designated emergency response zone code to which this checkpoint belongs for incident command and evacuation coordination. Aligns with the venue emergency response plan and law enforcement sector assignments.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `equipment_asset_tag` STRING COMMENT 'Physical asset tag or serial number of the primary screening equipment unit deployed at this checkpoint. Used for maintenance tracking, calibration scheduling, and asset lifecycle management in the facilities management system.. Valid values are `^[A-Z0-9-]{4,30}$`',
    `equipment_last_calibration_date` DATE COMMENT 'Date on which the primary screening equipment at this checkpoint was most recently calibrated and certified for operational use. Required for regulatory compliance and safety audits.',
    `equipment_next_calibration_date` DATE COMMENT 'Scheduled date for the next mandatory calibration of the primary screening equipment at this checkpoint. Triggers maintenance work orders and ensures continuous compliance with security equipment standards.',
    `event_type_applicability` STRING COMMENT 'Specifies the category of events for which this checkpoint is activated (e.g., all_events, sports_only, concerts_only, ppv_events, high_profile_only). Supports dynamic checkpoint activation planning across the event calendar. [ENUM-REF-CANDIDATE: all_events|sports_only|concerts_only|ppv_events|high_profile_only|private_events — promote to reference product]',
    `floor_level` STRING COMMENT 'Floor or level designation within the venue where this checkpoint is located (e.g., Ground, Level 1, Concourse, Basement). Used for emergency evacuation planning and facility management.',
    `gate_number` STRING COMMENT 'Physical gate or entrance number associated with this screening checkpoint as labeled on venue maps and patron-facing signage (e.g., Gate 1, Gate C, Loading Dock 3). Used for wayfinding and incident location reporting.',
    `is_ada_accessible` BOOLEAN COMMENT 'Indicates whether this screening checkpoint includes an ADA (Americans with Disabilities Act) compliant accessible lane for patrons with mobility impairments, wheelchairs, or other accessibility needs. Mandatory for venue ADA compliance reporting.',
    `is_express_lane` BOOLEAN COMMENT 'Indicates whether this checkpoint operates as an expedited screening lane for credentialed personnel, season ticket holders, VIP (Very Important Person) guests, or pre-screened patrons with reduced wait times.',
    `is_vehicle_checkpoint` BOOLEAN COMMENT 'Indicates whether this checkpoint is designated for vehicle inspection rather than pedestrian screening. Drives different equipment, staffing, and protocol requirements for parking lot and loading dock security.',
    `lane_count` STRING COMMENT 'Number of parallel screening lanes available at this checkpoint. A single checkpoint may have multiple lanes operating simultaneously to increase throughput capacity during peak ingress periods.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent formal safety and compliance inspection of this checkpoint by internal security management or an external regulatory authority. Supports OSHA compliance tracking and audit readiness.',
    `law_enforcement_post` BOOLEAN COMMENT 'Indicates whether this checkpoint requires a dedicated law enforcement officer (LEO) post as part of the security deployment plan. Drives coordination with local police, sheriff, or federal law enforcement agencies.',
    `max_queue_length_meters` DECIMAL(18,2) COMMENT 'Maximum physical queue length in meters that can be accommodated at this checkpoint before crowd management protocols are triggered. Used for ingress modeling and crowd density safety planning.',
    `min_staff_required` STRING COMMENT 'Minimum number of security personnel required to operate this checkpoint at baseline capacity. Used for staffing plans, shift scheduling, and SLA (Service Level Agreement) compliance with law enforcement partners.',
    `next_inspection_date` DATE COMMENT 'Scheduled date for the next mandatory safety and compliance inspection of this checkpoint. Triggers inspection work orders and ensures continuous regulatory compliance.',
    `notes` STRING COMMENT 'Free-text operational notes or special instructions for this checkpoint, such as known physical constraints, special event configurations, or temporary modifications. Used by security supervisors during event briefings.',
    `operating_sop_reference` STRING COMMENT 'Document reference number or URL for the Standard Operating Procedure (SOP) governing operations at this checkpoint type. Ensures staff follow approved protocols and supports compliance audits.',
    `optimal_staff_count` STRING COMMENT 'Recommended number of security personnel for this checkpoint to achieve rated throughput capacity. Distinct from minimum staffing — represents the target headcount for peak event operations.',
    `physical_location_description` STRING COMMENT 'Narrative description of the precise physical location of this checkpoint within the venue (e.g., North concourse, adjacent to Section 101 entrance, ground level). Supports emergency response coordination and incident reporting.',
    `primary_equipment_type` STRING COMMENT 'Primary security screening equipment deployed at this checkpoint. WTMD (Walk-Through Metal Detector), X-ray (baggage X-ray scanner), ETD (Explosive Trace Detection). Drives maintenance scheduling, calibration records, and procurement planning. [ENUM-REF-CANDIDATE: WTMD|X-ray|ETD|handheld_wand|visual_inspection|CCTV|vehicle_barrier — 7 candidates stripped; promote to reference product]',
    `prohibited_items_list_version` STRING COMMENT 'Version identifier of the prohibited items policy document governing what items are screened and confiscated at this checkpoint (e.g., v2.3). Ensures staff are operating under the current approved policy and supports audit traceability.. Valid values are `^vd+.d+$`',
    `security_level` STRING COMMENT 'Operational security threat level assigned to this checkpoint, which determines screening intensity, staffing multipliers, and equipment deployment. Aligns with DHS threat level frameworks and league-specific security mandates.. Valid values are `standard|elevated|high|critical`',
    `throughput_capacity_per_hour` STRING COMMENT 'Rated maximum number of persons that can be screened through this checkpoint per hour under normal operating conditions. Used for crowd management planning, staffing optimization, and event ingress modeling.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this screening checkpoint master record was most recently modified. Supports change tracking, audit compliance, and incremental data pipeline processing in the Databricks Silver layer.',
    `venue_zone_code` STRING COMMENT 'Alphanumeric code identifying the specific security zone or sector within the venue where this checkpoint is located (e.g., ZONE-A, CONCOURSE-2, FIELD-LEVEL). Aligns with venue access control zone mapping.',
    CONSTRAINT pk_screening_checkpoint PRIMARY KEY(`screening_checkpoint_id`)
) COMMENT 'Master record for all physical security screening checkpoints deployed at Sports Entertainment venues — magnetometer lanes, bag check stations, pat-down areas, vehicle inspection points, and credentialing desks. Captures checkpoint code, venue zone assignment, checkpoint type, equipment deployed (WTMD, X-ray, ETD), staffing requirement, throughput capacity (persons/hour), activation schedule, and ADA-accessible lane flag.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`screening_event` (
    `screening_event_id` BIGINT COMMENT 'Unique surrogate identifier for each individual screening interaction record at a security checkpoint. Primary key for the screening_event data product in the Databricks Silver Layer.',
    `access_zone_id` BIGINT COMMENT 'Foreign key linking to security.access_zone. Business justification: A screening event occurs at a checkpoint that controls entry to a specific access zone. The existing access_zone_code (STRING) is a denormalized text reference to the zone; replacing it with a proper ',
    `credential_id` BIGINT COMMENT 'Foreign key linking to security.credential. Business justification: A screening event involves a person presenting a credential for inspection. The screening_event table currently stores credential_number as a denormalized STRING, but the authoritative credential reco',
    `fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event during which this screening interaction took place. Enables post-event security review and cross-event trend analysis.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Screening events at franchise home games must be franchise-attributed for league fan safety compliance reporting, franchise-level throughput benchmarking, and CBA-mandated safety protocol audits requi',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-level screening aggregation is required for league annual safety compliance submissions, prohibited items trend analysis, and CBA player/fan safety reviews covering all franchise home games.',
    `membership_id` BIGINT COMMENT 'Foreign key linking to fan.membership. Business justification: VIP and season-ticket members use express/priority screening lanes. Linking screening events to membership records validates lane entitlement, audits express-lane usage compliance, and supports member',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Screening events are conducted under specific security and prohibited-items policies. Compliance audits of venue security operations require tracing each screening event to the governing policy versio',
    `fan_profile_id` BIGINT COMMENT 'Reference to the fan, staff member, or credentialed personnel who was screened. May be null for anonymous general admission screenings where identity is not captured.',
    `primary_screening_fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event during which this screening interaction took place. Enables post-event security review and cross-event trend analysis.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Athletes pass through security screening checkpoints at venues. Linking screening events to athlete profiles supports WADA whereabouts compliance documentation, security audit trails, and incident inv',
    `screening_checkpoint_id` BIGINT COMMENT 'Reference to the specific security checkpoint location where this screening interaction occurred. Used to analyze throughput and incident rates by checkpoint.',
    `security_incident_id` BIGINT COMMENT 'Foreign key linking to security.security_incident. Business justification: A screening event may trigger a security incident when a prohibited item is found, an individual is denied entry and becomes aggressive, or law enforcement is notified. The existing incident_report_nu',
    `venue_id` BIGINT COMMENT 'Reference to the venue facility where the screening occurred. Supports venue-level security performance benchmarking and ADA/OSHA compliance reporting.',
    `ada_accommodation_required_flag` BOOLEAN COMMENT 'Indicates whether the screened individual required an ADA accommodation during the screening process (e.g., wheelchair user, medical device wearer). Supports ADA compliance reporting and accessibility audit requirements.',
    `alarm_resolution` STRING COMMENT 'The resolution or explanation for an equipment alarm triggered during screening. Null when no alarm was triggered. Supports false-positive rate analysis and equipment calibration review.. Valid values are `false_positive|prohibited_item_found|medical_device|cleared_pat_down|unresolved`',
    `confiscation_receipt_number` STRING COMMENT 'Reference number issued to the individual when a prohibited item is confiscated, enabling item retrieval after the event if applicable. Null when no item was confiscated. Supports chain-of-custody documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this screening event record was first created in the system. Used for audit trail, data lineage, and Silver Layer ingestion tracking.',
    `credential_type` STRING COMMENT 'The type of access credential presented by the individual at the checkpoint (e.g., event ticket, staff badge, media credential). Used to validate authorized access and support post-event credentialing audits. [ENUM-REF-CANDIDATE: ticket|season_pass|staff_badge|media_credential|vendor_pass|vip_wristband — promote to reference product]. Valid values are `ticket|season_pass|staff_badge|media_credential|vendor_pass|vip_wristband`',
    `crowd_density_level` STRING COMMENT 'Operational assessment of crowd density at the checkpoint at the time of this screening interaction. Supports crowd management protocol activation analysis and post-event safety review.. Valid values are `low|moderate|high|critical`',
    `data_source_system` STRING COMMENT 'The operational system of record from which this screening event record was ingested into the Databricks Silver Layer (e.g., Ticketmaster/AXS, venue_access_control_system). Supports data lineage and audit trail requirements.',
    `entry_denied_reason` STRING COMMENT 'Free-text or coded reason why entry was denied to the screened individual. Null when entry was not denied. Supports denied-entry trend analysis and policy enforcement review.',
    `equipment_alarm_triggered_flag` BOOLEAN COMMENT 'Indicates whether the screening equipment (e.g., magnetometer, X-ray) triggered an alarm during this interaction. Distinguishes equipment-initiated alerts from officer-initiated secondary screenings.',
    `equipment_code` STRING COMMENT 'Identifier of the specific screening equipment unit used (e.g., magnetometer unit serial number, X-ray machine ID). Supports equipment maintenance tracking, calibration compliance, and fault correlation analysis.',
    `escalation_flag` BOOLEAN COMMENT 'Indicates whether this screening interaction was escalated beyond the initial checkpoint officer, such as to a supervisor, law enforcement, or medical personnel. Key field for post-event security review and incident management reporting.',
    `escalation_type` STRING COMMENT 'The type of escalation triggered by this screening interaction. Null or none when no escalation occurred. Used to categorize escalation patterns and resource deployment analysis.. Valid values are `supervisor|law_enforcement|medical|secondary_screening_team|none`',
    `gate_number` STRING COMMENT 'The physical gate or entry point identifier at the venue where the screening checkpoint is located. Used for throughput analysis and crowd flow management.',
    `item_confiscated_flag` BOOLEAN COMMENT 'Indicates whether the detected prohibited item was physically confiscated from the individual. Distinct from denied_entry outcome — an item may be confiscated while the individual is still permitted entry. Supports confiscation log and chain-of-custody tracking.',
    `lane_number` STRING COMMENT 'The specific screening lane within a checkpoint where the interaction occurred. Multiple lanes may operate at a single gate or checkpoint. Used for lane-level throughput and staffing analysis.',
    `law_enforcement_case_number` STRING COMMENT 'The official case or incident number assigned by law enforcement when they were notified or took action related to this screening event. Null when law enforcement was not involved. Enables cross-referencing with law enforcement records.',
    `law_enforcement_notified_flag` BOOLEAN COMMENT 'Indicates whether local or venue law enforcement was formally notified as part of this screening interaction. Supports law enforcement coordination reporting and incident documentation.',
    `notes` STRING COMMENT 'Free-text field for the screening officer to record additional observations, context, or details about the screening interaction not captured in structured fields. Used for incident documentation and post-event review.',
    `prohibited_item_category` STRING COMMENT 'High-level category of the prohibited item detected during screening. Null when no prohibited item was found. Supports trend analysis and policy review. [ENUM-REF-CANDIDATE: weapon_firearm|weapon_edged|weapon_blunt|explosive|controlled_substance|alcohol|oversized_bag|laser_device|other — promote to reference product]',
    `prohibited_item_description` STRING COMMENT 'Free-text description of the specific prohibited item detected (e.g., folding knife, 3-inch blade, half-pint whiskey flask). Null when no prohibited item was found. Used for detailed incident documentation and law enforcement reporting.',
    `prohibited_item_flag` BOOLEAN COMMENT 'Indicates whether a prohibited item was detected during this screening interaction. True when any prohibited item was found, regardless of whether it was confiscated or the individual was denied entry. Key driver for prohibited item trend analysis.',
    `queue_wait_time_seconds` STRING COMMENT 'The estimated or measured time in seconds the individual waited in the queue before reaching the screening checkpoint. Supports fan experience analysis, crowd management planning, and SLA reporting for entry operations.',
    `screened_person_type` STRING COMMENT 'Classification of the individual being screened, distinguishing fans from credentialed personnel, VIP guests, media, athletes, and law enforcement. Supports segmented security analytics and credentialing compliance. [ENUM-REF-CANDIDATE: fan|staff|vendor|media|vip|athlete|law_enforcement — promote to reference product]',
    `screening_duration_seconds` STRING COMMENT 'The elapsed time in seconds from the start to the completion of the screening interaction. Used for checkpoint throughput analysis, staffing optimization, and identifying bottlenecks in the fan entry process.',
    `screening_method` STRING COMMENT 'The physical or technological method used to conduct the screening. Supports equipment utilization analysis and compliance with venue security protocols. [ENUM-REF-CANDIDATE: walk_through_magnetometer|hand_wand|pat_down|bag_x_ray|visual_inspection|explosive_trace_detection — promote to reference product]. Valid values are `walk_through_magnetometer|hand_wand|pat_down|bag_x_ray|visual_inspection|explosive_trace_detection`',
    `screening_outcome` STRING COMMENT 'The result of the screening interaction indicating the disposition of the screened individual. Drives escalation workflows, prohibited item trend analysis, and checkpoint throughput reporting. [ENUM-REF-CANDIDATE: cleared|secondary_screening|denied_entry|prohibited_item_confiscated|medical_referral|law_enforcement_referral — promote to reference product]. Valid values are `cleared|secondary_screening|denied_entry|prohibited_item_confiscated|medical_referral|law_enforcement_referral`',
    `screening_reference_number` STRING COMMENT 'Externally-visible alphanumeric reference code assigned to this screening interaction, used for incident reporting, law enforcement coordination, and audit trail purposes. Format: SCR-{YEAR}-{EVENTID}-{SEQUENCE}.. Valid values are `^SCR-[0-9]{4}-[0-9]{8}-[A-Z0-9]{6}$`',
    `screening_timestamp` TIMESTAMP COMMENT 'The precise date and time when the screening interaction occurred at the checkpoint. Principal business event timestamp used for throughput analysis, timeline reconstruction, and post-event security review.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this screening event record was last modified, such as when an escalation outcome was updated or an incident report number was added. Supports audit trail and data quality monitoring.',
    CONSTRAINT pk_screening_event PRIMARY KEY(`screening_event_id`)
) COMMENT 'Transactional record of individual fan or personnel screening interactions at security checkpoints — capturing checkpoint ID, timestamp, screening outcome (cleared/secondary screening/denied entry/prohibited item confiscated), prohibited item type if applicable, officer ID, and escalation flag. Supports post-event security review, prohibited item trend analysis, and checkpoint throughput reporting.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`security_incident` (
    `security_incident_id` BIGINT COMMENT 'Unique surrogate identifier for each security incident record in the Sports Entertainment security management system. Primary key for the security_incident data product.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Security incident cost allocation is a core sports-venue finance process: medical response, law enforcement overtime, property damage, and legal liability costs must be charged to the responsible cost',
    `escalated_from_security_incident_id` BIGINT COMMENT 'Self-referencing FK on security_incident (escalated_from_security_incident_id)',
    `event_day_ops_id` BIGINT COMMENT 'Foreign key linking to venue.event_day_ops. Business justification: Security incidents must be linked to the event day ops record for post-event incident reporting, insurance claim correlation, and league governing body submissions. Event day ops tracks incident_count',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Security incidents at games are franchise-attributed for league disciplinary review, insurance claims, and competitive integrity reporting. League annual safety compliance reports aggregate incidents ',
    `game_result_id` BIGINT COMMENT 'Foreign key linking to league.game_result. Business justification: Security incidents affecting game play (field invasions, player altercations) must reference the certified game result for insurance claims, league integrity reviews, and protest adjudication. League ',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Security incident reports in sports venues must identify involved athletes (on-field altercations, locker room incidents, fan confrontations). League discipline, insurance claims, and broadcast disclo',
    `league_schedule_id` BIGINT COMMENT 'Foreign key linking to league.league_schedule. Business justification: Security incidents at games must reference the league schedule record for game-day incident management, post-game league reporting, and schedule impact assessment (postponements, forfeitures). League ',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-level incident aggregation is required for league safety compliance reporting, CBA player/fan safety provision reviews, and year-over-year trend analysis submitted to league governing bodies an',
    `membership_id` BIGINT COMMENT 'Foreign key linking to fan.membership. Business justification: League incident reporting and insurance claims require membership tier context at time of incident. VIP/season-ticket incidents trigger escalated CRM and legal protocols. Direct FK avoids multi-join t',
    `fixture_id` BIGINT COMMENT 'Reference to the specific Sports Entertainment event (game, concert, match) during which the security incident occurred. Enables event-level incident density analysis and post-event security debriefs.',
    `fan_profile_id` BIGINT COMMENT 'Reference to the registered fan profile in the CRM system (Salesforce CRM / Adobe Experience Platform) if the involved party is an identified fan. Enables cross-referencing with ticketing history, ban records, and loyalty status.',
    `retail_location_id` BIGINT COMMENT 'Foreign key linking to merchandise.retail_location. Business justification: Theft, fraud, and counterfeit-goods incidents occur at specific retail locations inside venues. Loss prevention reporting, insurance claims, and shrinkage analysis require attributing security inciden',
    `asset_id` BIGINT COMMENT 'Foreign key linking to content.asset. Business justification: Security incident investigations require linking to the DAM asset containing the surveillance footage clip. Post-incident review, insurance claims, and law enforcement handoff processes all depend on ',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Governing bodies (FIFA, IOC, UEFA) require tournament-level security incident aggregate reports for compliance and licensing. security_incident has fixture_id but no tournament_id; deriving tournament',
    `venue_id` BIGINT COMMENT 'Reference to the Sports Entertainment venue where the security incident occurred. Links to the venue master record for facility-level reporting and ADA/OSHA compliance tracking.',
    `ban_duration_days` STRING COMMENT 'Duration in days of the venue ban issued to the involved party. A value of -1 or null indicates a permanent ban. Populated when ban_issued is True.',
    `ban_issued` BOOLEAN COMMENT 'Indicates whether a venue ban or trespass notice was issued to the involved party as a result of this incident. Triggers downstream ban enforcement processes in Ticketmaster/AXS access control.',
    `closed_at` TIMESTAMP COMMENT 'Date and time the security incident case was formally closed following completion of all required actions, investigations, and documentation. Null if the incident remains open or under review.',
    `closure_notes` STRING COMMENT 'Free-text notes recorded at the time of case closure, summarizing final outcomes, follow-up actions completed, and any lessons learned for security operations improvement.',
    `created_at` TIMESTAMP COMMENT 'System-generated timestamp when the security incident record was first created in the data platform. Used for audit trail and data lineage purposes.',
    `credential_type_violated` STRING COMMENT 'Type of access credential involved in a credentialing violation incident (e.g., forged media pass, unauthorized field access badge). Populated when incident_type is credentialing_violation. [ENUM-REF-CANDIDATE: media|staff|vip|field_access|broadcast|vendor|athlete — 7 candidates stripped; promote to reference product]',
    `crowd_density_level` STRING COMMENT 'Estimated crowd density level in the incident zone at the time of the event. SRO (Standing Room Only) indicates maximum capacity. Used for crowd management protocol analysis and venue safety planning.. Valid values are `low|moderate|high|at_capacity|sro`',
    `disposition` STRING COMMENT 'Final outcome or action taken as a result of the security incident. Drives downstream processes including ban enforcement, medical referral, and law enforcement handoff. [ENUM-REF-CANDIDATE: ejected|arrested|warned|banned|referred_medical|no_action|trespass_notice|cited — promote to reference product]',
    `emergency_response_plan_activated` BOOLEAN COMMENT 'Indicates whether the venues formal Emergency Response Plan (ERP) was activated in response to this incident. Required for post-incident compliance review and insurance documentation.',
    `evacuation_triggered` BOOLEAN COMMENT 'Indicates whether the incident triggered a partial or full venue evacuation protocol. Drives post-incident emergency response plan review and regulatory reporting obligations.',
    `gate_identifier` STRING COMMENT 'Identifier of the entry/exit gate associated with the incident location, relevant for access control violations, prohibited item seizures, and credentialing breaches detected at ingress/egress points.',
    `incident_status` STRING COMMENT 'Current lifecycle state of the security incident case, tracking progression from initial report through investigation to final disposition and closure.. Valid values are `open|under_review|escalated|closed|voided`',
    `incident_type` STRING COMMENT 'Categorical classification of the security incident describing the nature of the event. [ENUM-REF-CANDIDATE: fan_altercation|ejection|prohibited_item_seizure|field_invasion|credentialing_violation|threat|suspicious_package|law_enforcement_intervention|trespassing|vandalism|theft|harassment — promote to reference product]',
    `insurance_claim_filed` BOOLEAN COMMENT 'Indicates whether an insurance claim was filed in connection with this security incident. Triggers financial reporting obligations and coordination with the Finance domain.',
    `insurance_claim_reference` STRING COMMENT 'Reference number for the insurance claim filed in connection with this incident. Confidential business data used for financial reconciliation in SAP S/4HANA. Populated when insurance_claim_filed is True.',
    `involved_party_id_number` STRING COMMENT 'Government-issued or venue-issued identification number (e.g., drivers license, passport, fan membership ID) for the primary involved party. Restricted PII used for law enforcement coordination and ban enforcement.',
    `involved_party_name` STRING COMMENT 'Full name of the primary individual involved in the security incident (subject, suspect, or victim). Classified as restricted PII under GDPR and CCPA. Required for law enforcement reporting and case management.',
    `involved_party_type` STRING COMMENT 'Classification of the primary party involved in or subject to the security incident. Determines applicable regulatory obligations (e.g., GDPR for fan data, CBA provisions for athlete incidents). [ENUM-REF-CANDIDATE: fan|athlete|staff|vendor|media|vip_guest|unknown — 7 candidates stripped; promote to reference product]',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency notified or involved in the incident response (e.g., NYPD, FBI Field Office, State Police). Populated when law_enforcement_notified is True.',
    `law_enforcement_case_number` STRING COMMENT 'Official case or report number assigned by the responding law enforcement agency. Used for cross-referencing with external law enforcement records and legal proceedings.',
    `law_enforcement_notified` BOOLEAN COMMENT 'Indicates whether local law enforcement (police, FBI, or other agency) was notified of the security incident. Required for regulatory reporting and incident severity escalation tracking.',
    `league_governing_body_reported` BOOLEAN COMMENT 'Indicates whether the incident was reported to the relevant league governing body (e.g., NFL, NBA, FIFA, NHL) per league security reporting obligations. Required for compliance with league security protocols and CBA provisions.',
    `medical_referral_required` BOOLEAN COMMENT 'Indicates whether the incident required a medical referral or emergency medical services (EMS) response. Triggers coordination with venue.safety_incident domain for OSHA recordkeeping when True.',
    `narrative` STRING COMMENT 'Free-text detailed description of the security incident as recorded by the responding officer, including sequence of events, actions taken, and any relevant contextual observations. Primary source for legal and insurance documentation.',
    `number_of_persons_involved` STRING COMMENT 'Total count of individuals directly involved in the security incident (subjects, victims, and witnesses). Used for incident severity assessment and resource deployment analysis.',
    `occurred_at` TIMESTAMP COMMENT 'The precise date and time the security incident occurred or was first observed, representing the principal real-world event time. Distinct from the record creation timestamp. Critical for timeline reconstruction and law enforcement reporting.',
    `prohibited_item_description` STRING COMMENT 'Free-text description of the specific prohibited item seized, including make, model, quantity, or other identifying characteristics. Supports chain-of-custody documentation and law enforcement handoff.',
    `prohibited_item_type` STRING COMMENT 'Classification of the prohibited item seized during the incident, applicable when incident_type is prohibited_item_seizure (e.g., weapon, alcohol, pyrotechnic, laser pointer, drone). [ENUM-REF-CANDIDATE: weapon|alcohol|pyrotechnic|laser_pointer|drone|controlled_substance|recording_device|other — promote to reference product]',
    `reference_number` STRING COMMENT 'Externally-known alphanumeric case number assigned at the time of incident creation, used for cross-system tracking, law enforcement reporting, and insurance claims. Format: SEC-YYYY-NNNNNN.. Valid values are `^SEC-[0-9]{4}-[0-9]{6}$`',
    `reported_at` TIMESTAMP COMMENT 'Date and time the incident was formally reported to the security operations center or duty manager, which may differ from the occurrence time. Used to measure reporting lag and response readiness.',
    `response_time_minutes` STRING COMMENT 'Elapsed time in minutes between the incident occurrence timestamp and the arrival of the first responding security officer. Key performance indicator (KPI) for security operations SLA compliance and staffing adequacy reviews.',
    `section_identifier` STRING COMMENT 'Specific section, block, or area designation within the venue zone where the incident took place (e.g., Section 112, Row G, Gate 4 Entry). Sourced from Archtics seating inventory for precise location mapping.',
    `severity_tier` STRING COMMENT 'Standardized severity classification assigned to the incident at time of reporting, used to prioritize response resources and escalation protocols. Tier 1 Critical requires immediate law enforcement; Tier 4 Low is handled by venue security staff.. Valid values are `tier_1_critical|tier_2_high|tier_3_medium|tier_4_low`',
    `surveillance_footage_available` BOOLEAN COMMENT 'Indicates whether CCTV or surveillance camera footage is available and has been preserved for this incident. Critical for evidence management, legal proceedings, and post-incident review.',
    `updated_at` TIMESTAMP COMMENT 'System-generated timestamp of the most recent modification to the security incident record, supporting audit trail requirements and change tracking.',
    `zone_code` STRING COMMENT 'Alphanumeric code identifying the access control zone within the venue where the incident occurred (e.g., GA-FLOOR, VIP-SUITE, FIELD-LEVEL, CONCOURSE-A). Aligns with Archtics venue seating and zone inventory definitions.',
    CONSTRAINT pk_security_incident PRIMARY KEY(`security_incident_id`)
) COMMENT 'Core transactional record for all security incidents occurring at Sports Entertainment venues and events — fan altercations, ejections, prohibited item seizures, field invasions, credentialing violations, threats, suspicious packages, and law enforcement interventions. Captures incident type, severity tier, location (zone/section/gate), involved parties, responding officers, law enforcement notification flag, medical referral flag, narrative, disposition, and case closure status. Distinct from venue.safety_incident which covers physical safety/OSHA events.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`ejection_record` (
    `ejection_record_id` BIGINT COMMENT 'Unique system-generated identifier for each ejection record. Primary key for the ejection_record data product within the security domain.',
    `access_entitlement_id` BIGINT COMMENT 'Foreign key linking to ticketing.access_entitlement. Business justification: Immediate entitlement voiding on ejection: when a fan is ejected, their access entitlement must be voided in real time to prevent re-entry. Security operations require a direct reference to the entitl',
    `calendar_id` BIGINT COMMENT 'Reference to the Sports Entertainment event during which the ejection occurred. Used to correlate ejection volume with event type, attendance, and security staffing levels.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Athletes are ejected from games for on-field conduct violations. Ejection records must reference the athlete profile to trigger league discipline reviews, suspension determinations, and broadcast repo',
    `official_id` BIGINT COMMENT 'Foreign key linking to league.official. Business justification: When a game official initiates an ejection, the ejection record must reference the specific official for officiating performance reviews and disciplinary accountability. ejecting_officer_badge is a de',
    `account_id` BIGINT COMMENT 'Reference to the fans CRM account record in Salesforce CRM, used to link the ejection to the fans profile for ban enforcement, repeat offender tracking, and communication history.',
    `fan_profile_id` BIGINT COMMENT 'Foreign key linking to fan.fan_profile. Business justification: Ejection history must be surfaced in the fan CRM profile for repeat-offender tracking, ban enforcement, and league regulatory reporting. The existing account link is insufficient for identity resoluti',
    `fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event during which the ejection occurred. Used to correlate ejection volume with event type, attendance, and security staffing levels.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Ejection records must be franchise-attributed for league disciplinary review, franchise-level fan conduct reporting, and CBA compliance covering fan safety provisions. League operations tracks ejectio',
    `game_result_id` BIGINT COMMENT 'Foreign key linking to league.game_result. Business justification: Ejection records must be tied to the official game result for post-game disciplinary review, league integrity reporting, and game certification. League operations teams cross-reference ejections with ',
    `investigation_id` BIGINT COMMENT 'Foreign key linking to compliance.investigation. Business justification: Ejections involving serious misconduct (assault, racism, repeat offenders) escalate to formal compliance investigations for league conduct review and regulatory reporting. Security operations teams ne',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped ejection aggregation is required for league annual fan conduct reports, franchise compliance reviews, and year-over-year safety trend analysis submitted to league governing bodies.',
    `membership_id` BIGINT COMMENT 'Foreign key linking to fan.membership. Business justification: Ejection records for season ticket holders and members must reference the active membership for ban enforcement (membership suspension/revocation), season ticket revocation decisions, and legal docume',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Ejections are executed under specific fan conduct policies (code of conduct, zero-tolerance policy). Fan conduct enforcement, appeals processing, and legal defense of ejection decisions require tracin',
    `security_incident_id` BIGINT COMMENT 'Reference to the originating security incident record that triggered this ejection. Links the ejection to the broader incident context including initial report, escalation chain, and responding officers.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to content.asset. Business justification: Ejection records require structured references to surveillance footage assets for fan ban appeals, law enforcement handoff, and ban registry documentation. The current surveillance_clip_reference is a',
    `ticket_order_id` BIGINT COMMENT 'Foreign key linking to ticketing.ticket_order. Business justification: Ejection-to-order workflow: when a fan is ejected, the ticket order must be identified to void remaining access, initiate applicable refunds, and flag the account for ban enforcement. ejection_record.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where the ejection took place. Supports venue-level security analytics, staffing benchmarks, and ADA/OSHA compliance reporting.',
    `appeal_filed_flag` BOOLEAN COMMENT 'Indicates whether the ejected individual has formally filed an appeal against the ejection decision. True = appeal filed; False = no appeal filed. Triggers the ejection review workflow and updates ejection_status to appealed.',
    `appeal_resolution_date` DATE COMMENT 'The date on which the formal appeal of the ejection was resolved. Populated when ejection_status transitions to upheld or overturned. Used for SLA (Service Level Agreement) tracking of the appeals process.',
    `arrest_made_flag` BOOLEAN COMMENT 'Indicates whether the ejected individual was formally arrested by law enforcement at or following the ejection. True = arrest was made; False = no arrest. Relevant for legal proceedings, insurance claims, and ban severity determination.',
    `ban_recommendation_flag` BOOLEAN COMMENT 'Indicates whether the ejecting officer or supervisor has recommended a venue ban for the ejected individual. True = ban recommended; False = no ban recommended. Feeds the venue ban registry workflow for formal ban issuance.',
    `ban_registry_reference` BIGINT COMMENT 'Reference to the formal ban record created in the venue ban registry as a result of this ejection. Populated after the ban is formally issued following the recommendation workflow. Null if no ban was issued.',
    `ban_type` STRING COMMENT 'Classification of the recommended or issued ban scope. Populated when ban_recommendation_flag is True. Drives the ban registry entry type and enforcement duration. [ENUM-REF-CANDIDATE: single_event|season|multi_season|lifetime|league_wide — promote to reference product]. Valid values are `single_event|season|multi_season|lifetime|league_wide`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this ejection record was first created in the system. Represents the audit trail creation time, distinct from the ejection_timestamp which captures the real-world event time. Required for data lineage and compliance audit trails.',
    `crowd_density_level` STRING COMMENT 'Assessed crowd density level in the ejection zone at the time of the incident. Used for crowd management analysis, security staffing optimization, and post-event safety reviews. Aligns with ISO 20121 event sustainability and safety management standards.. Valid values are `low|moderate|high|critical`',
    `data_source_system` STRING COMMENT 'Identifies the operational system of record from which this ejection record originated or was primarily sourced. Supports data lineage tracking and Silver Layer reconciliation in the Databricks Lakehouse.. Valid values are `ticketmaster_axs|salesforce_crm|manual_entry|archtics|adobe_experience_platform`',
    `ejected_party_id_number` STRING COMMENT 'The identification document number (e.g., drivers license number, passport number) of the ejected individual as recorded for ban enforcement and law enforcement handoff. Stored in compliance with GDPR and CCPA data minimization principles.',
    `ejected_party_id_type` STRING COMMENT 'Type of identification document presented or used to identify the ejected individual at the time of ejection. Supports identity verification for ban enforcement and law enforcement handoff.. Valid values are `drivers_license|passport|national_id|fan_membership_card|employee_badge|none_presented`',
    `ejected_party_name` STRING COMMENT 'Full name of the individual who was ejected, as recorded at the time of ejection from identification documents or ticketing records. Required for ban enforcement, law enforcement handoff documentation, and legal proceedings.',
    `ejected_party_type` STRING COMMENT 'Classification of the type of individual who was ejected. Determines the applicable code of conduct, ban enforcement pathway, and reporting requirements. VIP (Very Important Person) guests and media personnel follow distinct escalation protocols.. Valid values are `fan|staff|media|vendor|athlete|vip_guest`',
    `ejection_reason_code` STRING COMMENT 'Standardized reason code classifying the primary cause of the ejection. Drives ban recommendation logic, repeat offender scoring, and regulatory reporting. [ENUM-REF-CANDIDATE: intoxication|fighting|field_invasion|harassment|prohibited_item|threatening_behavior|racial_abuse|ticket_fraud — promote to reference product]',
    `ejection_reason_description` STRING COMMENT 'Free-text narrative description of the specific circumstances leading to the ejection, as recorded by the ejecting security officer. Supplements the standardized reason code with contextual detail for incident review and legal proceedings.',
    `ejection_reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to this ejection at the time of occurrence, used in law enforcement handoff documentation, ban notices, and fan appeals. Format: EJ-{YYYY}-{NNNNNN}.. Valid values are `^EJ-[0-9]{4}-[0-9]{6}$`',
    `ejection_status` STRING COMMENT 'Current lifecycle state of the ejection record. pending indicates the ejection is being processed; confirmed means the ejection is finalized; appealed means the ejected party has filed a formal appeal; overturned means the ejection was reversed upon review; upheld means the ejection was sustained after appeal.. Valid values are `pending|confirmed|appealed|overturned|upheld`',
    `ejection_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the ejection was executed — i.e., when the individual physically exited or was removed from the venue. This is the principal real-world business event time, distinct from when the record was created in the system.',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency to which the ejected individual was handed off (e.g., NYPD, LAPD, Stadium Authority Police). Populated only when law_enforcement_handoff_flag is True.',
    `law_enforcement_case_number` STRING COMMENT 'The official case or report number assigned by the receiving law enforcement agency at the time of handoff. Used for cross-referencing with police records and legal proceedings.',
    `law_enforcement_handoff_flag` BOOLEAN COMMENT 'Indicates whether the ejected individual was handed off to law enforcement (police, stadium security authority) at the time of ejection. True = law enforcement was involved; False = internal security handled the ejection without law enforcement transfer.',
    `medical_assistance_required_flag` BOOLEAN COMMENT 'Indicates whether medical assistance was required for the ejected individual or any other party involved in the incident (e.g., intoxication requiring EMT response, injury from altercation). True = medical assistance was provided or requested; False = no medical assistance needed.',
    `prior_ejection_count` STRING COMMENT 'The number of prior ejections on record for this individual at the time of this ejection event. Used to determine escalation thresholds for ban recommendations and repeat offender classification. Sourced from the ejection history at time of record creation.',
    `prohibited_item_description` STRING COMMENT 'Description of any prohibited item(s) found on or associated with the ejected individual. Populated when ejection_reason_code is prohibited_item. Includes item type, quantity, and disposition (confiscated, surrendered, etc.).',
    `repeat_offender_flag` BOOLEAN COMMENT 'Indicates whether the ejected individual has a prior ejection record within the Sports Entertainment system at the time of this ejection. True = prior ejection(s) on record; False = first-time ejection. Drives escalated ban recommendations and repeat offender tracking workflows.',
    `seat_number` STRING COMMENT 'The specific seat number assigned to the ejected individual within their row and section. Enables precise location correlation with ticketing records for ban enforcement and refund processing.',
    `seat_row` STRING COMMENT 'The row identifier within the seating section where the ejected individual was located. Used in conjunction with seat_section and seat_number for precise location tracking and witness identification.',
    `seat_section` STRING COMMENT 'The seating section identifier (e.g., 114, GA, SRO) where the ejected individual was located at the time of the incident, as recorded in Archtics or Ticketmaster/AXS access control systems.',
    `surveillance_footage_available_flag` BOOLEAN COMMENT 'Indicates whether surveillance camera footage of the ejection incident is available and has been flagged for retention. True = footage available and retained; False = no footage available. Supports legal proceedings, appeals, and security system audits.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this ejection record was most recently modified. Tracks updates to ejection status, ban recommendations, appeal outcomes, and law enforcement case numbers. Required for data lineage and Silver Layer change tracking.',
    `venue_zone_code` STRING COMMENT 'Alphanumeric code identifying the specific zone or section of the venue where the ejection incident originated, as defined in the Archtics venue seating and inventory management system (e.g., SEC-114, FIELD-LEVEL, CONCOURSE-B). Used for crowd management hotspot analysis.',
    `venue_zone_type` STRING COMMENT 'Classification of the venue zone where the ejection occurred. Supports access control analysis and security resource allocation by zone category. [ENUM-REF-CANDIDATE: seating_bowl|field_level|concourse|vip_suite|media_zone|backstage|parking|entry_gate — promote to reference product]',
    CONSTRAINT pk_ejection_record PRIMARY KEY(`ejection_record_id`)
) COMMENT 'Transactional record of every fan or personnel ejection from a Sports Entertainment venue or event. Captures ejection date/time, venue zone, reason code (intoxication, fighting, field invasion, harassment, prohibited item), ejecting officer, law enforcement handoff flag, ban recommendation flag, originating security incident reference, and fan account reference for ban enforcement. Feeds the venue ban registry and repeat offender tracking.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`emergency_response_plan` (
    `emergency_response_plan_id` BIGINT COMMENT 'Unique surrogate identifier for each emergency response plan record in the Sports Entertainment security domain.',
    `fixture_id` BIGINT COMMENT 'Reference to a specific Sports Entertainment event for which this plan is activated or scoped. Null when the plan applies to the venue generally rather than a single event.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Emergency response plans are developed per franchise home venue context. Franchise linkage enables franchise-specific plan compliance tracking, league safety audits, and regulatory submissions tied to',
    `governing_body_id` BIGINT COMMENT 'Foreign key linking to compliance.governing_body. Business justification: Emergency response plans at sports venues require approval from governing bodies (DHS, league authorities, local fire marshal authorities tracked in compliance). The ERP already tracks dhs_approval_st',
    `league_id` BIGINT COMMENT 'Foreign key linking to league.league. Business justification: Emergency response plans are mandated and governed at the league level (league-wide safety standards, CBA requirements). League compliance officers manage ERP approval and audit across all franchises.',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped emergency plans are required for league annual safety compliance and DHS coordination. Season tagging enables plan version management aligned to league season lifecycle and CBA safety pr',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: Emergency response plans are created to fulfill specific regulatory obligations (fire safety, DHS venue security requirements, league safety mandates). Compliance tracking requires linking each plan t',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Emergency response plans are mandated by and must comply with specific safety and security policies (DHS SAFETY Act, venue safety policy, league emergency protocols). Compliance audits of emergency pr',
    `primary_superseded_by_plan_emergency_response_plan_id` BIGINT COMMENT 'Reference to the newer emergency response plan that has replaced this version. Null if this is the current active version. Enables version chain traceability for audit and regulatory review.',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Tournament-level ERPs (FIFA World Cup, Olympic Games, championship tournaments) are a distinct operational construct from fixture-level ERPs. Governing bodies require tournament-scoped emergency plann',
    `venue_id` BIGINT COMMENT 'Reference to the Sports Entertainment venue to which this emergency response plan applies. A plan may be venue-specific or cover multiple venues (see multi_venue_flag).',
    `activation_trigger` STRING COMMENT 'Narrative description of the specific conditions or thresholds that trigger activation of this emergency response plan (e.g., Confirmed armed individual on premises, NWS Tornado Warning issued within 10-mile radius). Critical for incident command decision-making.',
    `ada_accommodation_provisions` STRING COMMENT 'Description of specific provisions within this plan for evacuating and sheltering guests and staff with disabilities, including wheelchair-accessible evacuation routes, Areas of Rescue Assistance (ARA), and mobility assistance protocols.',
    `communication_protocol` STRING COMMENT 'Description of the communication systems and protocols used during plan activation, including radio frequencies, PA system codes, mass notification system triggers, and social media blackout procedures.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this emergency response plan record was first created in the Sports Entertainment security data platform. Supports audit trail and regulatory document control requirements.',
    `crowd_capacity_threshold` STRING COMMENT 'Minimum crowd attendance count at which this plans enhanced protocols are activated (e.g., plans may have tiered activation based on event size). Supports DHS Special Event Assessment Rating (SEAR) classification.',
    `dhs_approval_date` DATE COMMENT 'Date on which DHS formally approved this emergency response plan. Null if approval is pending, not required, or rejected.',
    `dhs_approval_status` STRING COMMENT 'Regulatory approval status of this plan with the U.S. Department of Homeland Security. Required for events classified under DHS Special Event Assessment Rating (SEAR) Tier I-III.. Valid values are `pending|submitted|approved|rejected|not_required`',
    `effective_date` DATE COMMENT 'Calendar date on which this version of the emergency response plan becomes operationally binding. Used to determine which plan version is active for a given event date.',
    `expiry_date` DATE COMMENT 'Calendar date on which this emergency response plan version expires and must be reviewed or renewed. Null for open-ended plans. Drives regulatory renewal workflows and compliance alerts.',
    `fire_marshal_approval_date` DATE COMMENT 'Date on which the local fire marshal formally approved this emergency response plan. Null if approval is pending, not required, or rejected.',
    `fire_marshal_approval_status` STRING COMMENT 'Regulatory approval status of this plan with the local fire marshal authority. Required for all venue events under NFPA 101 and local fire codes. Drives event permit issuance.. Valid values are `pending|submitted|approved|rejected|not_required`',
    `fire_marshal_contact` STRING COMMENT 'Primary contact phone number for the local fire marshal office responsible for approving and coordinating fire evacuation components of this plan. Required for regulatory compliance.',
    `incident_command_structure` STRING COMMENT 'Description of the Incident Command System (ICS) hierarchy governing this plan, including Incident Commander role, Operations Section Chief, Safety Officer, and Public Information Officer designations per NIMS ICS standards.',
    `incident_commander_name` STRING COMMENT 'Full name of the designated Incident Commander responsible for directing emergency response operations under this plan. Confidential operational security information.',
    `incident_commander_title` STRING COMMENT 'Official job title of the designated Incident Commander (e.g., Director of Event Security, VP Venue Operations). Used in regulatory filings and law enforcement coordination documents.',
    `last_drill_date` DATE COMMENT 'Date of the most recent tabletop exercise or full-scale drill conducted to validate this emergency response plan. Required for OSHA compliance and DHS preparedness certification.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this emergency response plan record. Used for change tracking, regulatory audit trails, and Silver Layer data lineage in the Databricks Lakehouse.',
    `law_enforcement_agency` STRING COMMENT 'Name of the primary law enforcement agency coordinating with Sports Entertainment under this plan (e.g., Las Vegas Metropolitan Police Department, NYPD Special Events Unit). Required for DHS Special Event Assessment Rating (SEAR) submissions.',
    `law_enforcement_contact` STRING COMMENT 'Primary contact phone number or radio channel for law enforcement coordination during activation of this plan. Confidential operational security data restricted to authorized security personnel.',
    `media_blackout_flag` BOOLEAN COMMENT 'Indicates whether this plan includes a media and social media blackout protocol during initial activation to prevent panic, protect operational security, and manage public communications through official channels only.',
    `medical_triage_zone_count` STRING COMMENT 'Number of designated medical triage zones established under this plan for mass casualty incident (MCI) response. Drives medical resource pre-positioning and EMS coordination planning.',
    `multi_venue_flag` BOOLEAN COMMENT 'Indicates whether this emergency response plan applies to multiple venues simultaneously (e.g., a league-wide severe weather protocol). When True, venue_id represents the primary venue and additional venues are linked in a separate association table.',
    `mutual_aid_agreement_ref` STRING COMMENT 'Reference number or name of the mutual aid agreement with external agencies (neighboring jurisdictions, hospitals, EMS providers) that supports this plan. Enables cross-agency resource sharing during large-scale incidents.',
    `next_review_date` DATE COMMENT 'Scheduled date for the next mandatory review and update of this emergency response plan. Drives compliance calendar alerts and ensures plans remain current with regulatory changes and venue modifications.',
    `plan_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this emergency response plan across venues and regulatory submissions (e.g., ERP-FIRE-2024-001). Used in DHS filings, local fire marshal submissions, and law enforcement coordination documents.. Valid values are `^ERP-[A-Z]{2,6}-[0-9]{4}-[0-9]{3}$`',
    `plan_document_url` STRING COMMENT 'Secure URL to the full emergency response plan document stored in the Sports Entertainment Digital Asset Management (DAM) system. Access restricted to authorized security and compliance personnel. Confidential operational security document.',
    `plan_name` STRING COMMENT 'Human-readable title of the emergency response plan (e.g., Active Shooter Response Plan – Allegiant Stadium 2024). Used in operational briefings, staff training materials, and regulatory filings.',
    `plan_owner_department` STRING COMMENT 'Organizational department responsible for this emergency response plan (e.g., Venue Security Operations, Event Safety and Compliance, Facilities Management).',
    `plan_owner_name` STRING COMMENT 'Full name of the Sports Entertainment staff member accountable for maintaining, updating, and submitting this emergency response plan. Confidential internal personnel data.',
    `plan_status` STRING COMMENT 'Current lifecycle state of the emergency response plan. Active indicates the plan is operationally deployed; superseded indicates a newer version has replaced it; retired indicates the plan is no longer applicable.. Valid values are `draft|under_review|approved|active|superseded|retired`',
    `plan_type` STRING COMMENT 'Classification of the emergency scenario this plan governs. Drives protocol selection, command structure, and law enforcement coordination requirements. [ENUM-REF-CANDIDATE: active_shooter|bomb_threat|mass_casualty|fire_evacuation|severe_weather|medical_emergency — promote to reference product if additional types are needed]. Valid values are `active_shooter|bomb_threat|mass_casualty|fire_evacuation|severe_weather|medical_emergency`',
    `primary_triage_zone_location` STRING COMMENT 'Physical location description of the primary medical triage zone within the venue (e.g., Gate A Concourse Level 1, Field Level South End Zone). Used by EMS and medical staff during MCI activation.',
    `public_address_code` STRING COMMENT 'Standardized code word or phrase used in venue public address announcements to signal activation of this plan without causing public panic (e.g., Code Alpha for medical emergency, Code Bravo for security threat).',
    `regulatory_jurisdiction` STRING COMMENT 'Geographic and regulatory jurisdiction governing this plan (e.g., Clark County, Nevada, City of New York, NY, Federal – DHS Tier 1). Determines which regulatory bodies must approve the plan.',
    `sear_tier` STRING COMMENT 'DHS Special Event Assessment Rating tier assigned to events covered by this plan. Tier 1 represents the highest national significance (e.g., Super Bowl, Olympics); Tier 3 represents significant regional events. Determines federal resource allocation and coordination requirements.. Valid values are `tier_1|tier_2|tier_3|not_classified`',
    `shelter_in_place_zone` STRING COMMENT 'Designated venue area(s) for shelter-in-place protocols, applicable for severe weather, active threat, or hazmat scenarios. Includes interior hardened areas, concourse corridors, and below-grade spaces.',
    `threat_level` STRING COMMENT 'Severity classification of the emergency scenario addressed by this plan, aligned with DHS threat level taxonomy. Drives resource pre-positioning, law enforcement notification thresholds, and public communication protocols.. Valid values are `low|moderate|high|critical`',
    `version_number` STRING COMMENT 'Semantic version identifier for this iteration of the emergency response plan (e.g., 2.1.0). Enables tracking of plan revisions, regulatory re-submissions, and audit trails across plan lifecycle.. Valid values are `^[0-9]+.[0-9]+(.[0-9]+)?$`',
    CONSTRAINT pk_emergency_response_plan PRIMARY KEY(`emergency_response_plan_id`)
) COMMENT 'Master record for all emergency response plans governing Sports Entertainment venues and events — active shooter protocols, bomb threat procedures, mass casualty incident (MCI) response, fire evacuation, severe weather shelter-in-place, and medical emergency escalation. Captures plan type, venue scope, version, activation triggers, command structure, law enforcement coordination contacts, medical triage zone assignments, and regulatory approval status (DHS, local fire marshal).';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`emergency_activation` (
    `emergency_activation_id` BIGINT COMMENT 'Unique surrogate identifier for each emergency response plan activation record. Primary key for the emergency_activation data product. Entity role: TRANSACTION_HEADER — discrete business event with a clear lifecycle.',
    `production_id` BIGINT COMMENT 'Foreign key linking to broadcast.production. Business justification: Emergency activations that interrupt live broadcasts must reference the specific broadcast production for incident command coordination, insurance claims, and regulatory reporting. emergency_activatio',
    `emergency_response_plan_id` BIGINT COMMENT 'Reference to the specific emergency response plan document that was activated. Links to the plan registry for version control and compliance tracking.',
    `escalated_emergency_activation_id` BIGINT COMMENT 'Self-referencing FK on emergency_activation (escalated_emergency_activation_id)',
    `event_day_ops_id` BIGINT COMMENT 'Foreign key linking to venue.event_day_ops. Business justification: Emergency activations must be correlated to the specific event day ops record for after-action reporting, insurance claims, and league regulatory submissions. Venue operations and security teams joint',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Emergency activations at franchise home games must be franchise-attributed for league incident reporting, insurance claims, and CBA player safety compliance reviews. League tracks activations by franc',
    `investigation_id` BIGINT COMMENT 'Foreign key linking to compliance.investigation. Business justification: Emergency activations resulting in injuries, fatalities, or regulatory scrutiny trigger formal compliance investigations. Post-incident regulatory inquiries (crowd crush, terrorism response) require t',
    `league_schedule_id` BIGINT COMMENT 'Foreign key linking to league.league_schedule. Business justification: Emergency activations during games trigger game suspension or cancellation decisions that must reference the league schedule. League operations and broadcast teams need this link to manage schedule im',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-level emergency activation records are required for league annual safety reports, regulatory filings, and CBA compliance reviews covering player and fan safety provisions across the full season',
    `live_feed_id` BIGINT COMMENT 'Foreign key linking to broadcast.live_feed. Business justification: When an emergency interrupts a live broadcast, the specific live feed that was suspended must be recorded for after-action reports, broadcaster notification obligations, and insurance claims. emergenc',
    `fixture_id` BIGINT COMMENT 'Reference to the Sports Entertainment event (game, concert, match, etc.) during which this emergency activation occurred. Links activation to the event scheduling and ticketing context.',
    `security_incident_id` BIGINT COMMENT 'Foreign key linking to security.security_incident. Business justification: An emergency activation is often triggered by a specific security incident — a bomb threat, mass casualty event, or severe altercation that escalates to emergency response plan activation. The existin',
    `venue_id` BIGINT COMMENT 'Reference to the Sports Entertainment venue where the emergency activation was executed. Supports venue-level safety compliance reporting and ADA/OSHA audit trails.',
    `activation_number` STRING COMMENT 'Externally-known, human-readable business identifier for this emergency activation event (e.g., EMA-2024-000123). Used in after-action reports, law enforcement coordination, and regulatory filings. Serves as the BUSINESS_IDENTIFIER category for TRANSACTION_HEADER role.. Valid values are `^EMA-[0-9]{4}-[0-9]{6}$`',
    `activation_source` STRING COMMENT 'Identifies how the emergency activation was triggered: manually by an authorized officer, automatically by an alarm or surveillance system, or reported by law enforcement, staff, or fans. Supports root cause analysis and system effectiveness evaluation.. Valid values are `manual|automated_alarm|surveillance_system|law_enforcement|staff_report|fan_report`',
    `activation_status` STRING COMMENT 'Current lifecycle state of the emergency activation. Tracks progression from initial activation through resolution or transfer to external authority. Serves as the LIFECYCLE_STATUS category for TRANSACTION_HEADER role. [ENUM-REF-CANDIDATE: active|contained|resolved|cancelled|escalated|transferred — promote to reference product if additional states are required]. Valid values are `active|contained|resolved|cancelled|escalated|transferred`',
    `activation_timestamp` TIMESTAMP COMMENT 'The precise date and time when the emergency response plan was formally activated. This is the principal real-world business event timestamp (BUSINESS_EVENT_TIMESTAMP category). Recorded in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX).',
    `after_action_report_reference` STRING COMMENT 'Document reference number or URL linking to the formal After-Action Report (AAR) completed following this emergency activation. The AAR documents lessons learned, response effectiveness, and corrective actions. Required for OSHA, ISO 20121, and league governance compliance.',
    `after_action_report_status` STRING COMMENT 'Current completion status of the After-Action Report (AAR) for this emergency activation. Tracks compliance with mandatory post-incident review requirements.. Valid values are `pending|in_progress|completed|approved|waived`',
    `all_clear_timestamp` TIMESTAMP COMMENT 'The date and time when the all-clear signal was officially issued, indicating the emergency has been resolved and normal operations may resume. Null if the activation has not yet been resolved. Used to calculate response duration.',
    `broadcast_interrupted` BOOLEAN COMMENT 'Indicates whether live broadcast operations (TV, OTT, radio) were interrupted or suspended as a result of this emergency activation. Relevant for media rights compliance, FCC reporting, and broadcast partner SLA management.',
    `command_post_location` STRING COMMENT 'Physical location description of the Incident Command Post (ICP) established for this emergency activation (e.g., Gate C Security Office, Parking Lot B Mobile Command Unit). Critical for coordinating multi-agency response and documenting ICS compliance.',
    `confirmed_fatalities_count` STRING COMMENT 'Total number of confirmed fatalities recorded as a direct result of the emergency incident. Triggers mandatory OSHA fatality reporting within 8 hours, executive notification, and regulatory investigation protocols.',
    `confirmed_injuries_count` STRING COMMENT 'Total number of confirmed injuries (non-fatal) recorded as a direct result of the emergency incident. Used for OSHA 300 log reporting, insurance claims, and after-action analysis.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this emergency activation record was first created in the system. Serves as the RECORD_AUDIT_CREATED category for TRANSACTION_HEADER role. Supports data lineage and audit trail requirements.',
    `drill_exercise` BOOLEAN COMMENT 'Indicates whether this activation record represents a planned emergency drill or tabletop exercise rather than an actual emergency event. Allows filtering of drill records from operational incident analytics and regulatory reporting.',
    `ems_notified` BOOLEAN COMMENT 'Indicates whether Emergency Medical Services (EMS) was formally notified as part of this emergency activation. Mandatory documentation for mass casualty and medical emergency plan types.',
    `estimated_occupancy_at_activation` STRING COMMENT 'Estimated number of persons (fans, staff, athletes, media) present in the venue at the time of emergency activation. Critical for resource allocation, casualty ratio calculations, and post-event safety analysis. Serves as the QUANTITATIVE_RESULT category for this non-monetary TRANSACTION_HEADER.',
    `evacuation_initiated` BOOLEAN COMMENT 'Indicates whether a full or partial venue evacuation was initiated as part of this emergency activation. Drives crowd management protocol tracking and post-event safety audit requirements.',
    `evacuation_type` STRING COMMENT 'Specifies the scope of evacuation executed during this emergency activation: full venue, partial (specific sections), sector-specific (single zone), or none. Applicable only when evacuation_initiated is True.. Valid values are `full|partial|sector_specific|none`',
    `event_cancelled` BOOLEAN COMMENT 'Indicates whether the Sports Entertainment event was fully cancelled (not resumed) as a result of this emergency activation. Triggers ticketing refund workflows, force majeure clauses, and insurance claim processes.',
    `event_suspended` BOOLEAN COMMENT 'Indicates whether the Sports Entertainment event (game, concert, match) was formally suspended or halted as a result of this emergency activation. Impacts ticketing refund obligations, broadcast rights, and league governance reporting.',
    `false_alarm` BOOLEAN COMMENT 'Indicates whether this emergency activation was subsequently determined to be a false alarm (no actual emergency existed). Critical for tracking false alarm rates, system calibration, and regulatory reporting to fire/police authorities.',
    `fbi_notified` BOOLEAN COMMENT 'Indicates whether the Federal Bureau of Investigation (FBI) was formally notified as part of this emergency activation. Required for terrorism, active shooter, and bomb threat plan types per federal reporting obligations.',
    `fire_department_notified` BOOLEAN COMMENT 'Indicates whether the fire department was formally notified as part of this emergency activation. Required for NFPA 101 and OSHA compliance documentation.',
    `incident_commander_name` STRING COMMENT 'Full name of the designated Incident Commander (IC) who assumed operational control of the emergency response under the Incident Command System (ICS). May differ from the activating authority if command was transferred.',
    `incident_severity_level` STRING COMMENT 'Standardized severity classification of the emergency incident at time of activation (Level 1 = minor/localized to Level 5 = catastrophic/mass casualty). Drives resource mobilization, agency notification requirements, and executive escalation protocols.. Valid values are `level_1|level_2|level_3|level_4|level_5`',
    `incident_trigger_description` STRING COMMENT 'Narrative description of the specific incident, condition, or threat that triggered the emergency plan activation. Captures the initiating event details for after-action review and regulatory reporting.',
    `insurance_claim_filed` BOOLEAN COMMENT 'Indicates whether an insurance claim has been filed in connection with this emergency activation. Triggers financial reporting workflows and links to the finance domain for claim tracking.',
    `lockdown_initiated` BOOLEAN COMMENT 'Indicates whether a venue lockdown (perimeter secured, no entry/exit permitted) was initiated as part of this emergency activation. Critical for active shooter and terrorism threat plan types.',
    `medical_transports_count` STRING COMMENT 'Number of individuals transported by EMS or other medical transport to off-site medical facilities during or immediately following the emergency activation. Supports EMS coordination reporting and insurance documentation.',
    `plan_type` STRING COMMENT 'Classification of the type of emergency response plan activated. Determines the response protocol, agencies notified, and command structure engaged. [ENUM-REF-CANDIDATE: evacuation|shelter_in_place|medical_emergency|fire|security_threat|natural_disaster|crowd_crush|bomb_threat|active_shooter — promote to reference product]',
    `police_notified` BOOLEAN COMMENT 'Indicates whether law enforcement (police) was formally notified as part of this emergency activation. Required for regulatory compliance documentation and after-action reporting.',
    `regulatory_report_filed` BOOLEAN COMMENT 'Indicates whether a mandatory regulatory report (e.g., OSHA fatality/hospitalization report, FCC emergency alert report, local authority notification) has been filed for this emergency activation.',
    `regulatory_report_reference` STRING COMMENT 'Reference number or tracking identifier for the regulatory report filed with the applicable authority (OSHA, FCC, local emergency management). Populated only when regulatory_report_filed is True.',
    `response_duration_minutes` STRING COMMENT 'Total elapsed time in minutes from activation_timestamp to all_clear_timestamp. Captured as a stored business metric (not derived at query time) to support SLA compliance reporting and benchmarking against emergency response KPI targets.',
    `shelter_in_place_initiated` BOOLEAN COMMENT 'Indicates whether a shelter-in-place directive was issued to venue occupants as part of this emergency activation. Mutually exclusive with full evacuation in most scenarios.',
    `threat_category` STRING COMMENT 'Broad category of the threat or hazard that prompted the emergency activation. Used for trend analysis, risk modeling, and compliance reporting across venue and event portfolios. [ENUM-REF-CANDIDATE: physical|medical|environmental|structural|cyber|crowd|weather|terrorism — 8 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this emergency activation record was most recently modified. Serves as the RECORD_AUDIT_UPDATED category for TRANSACTION_HEADER role. Supports change tracking and Silver Layer data freshness monitoring.',
    CONSTRAINT pk_emergency_activation PRIMARY KEY(`emergency_activation_id`)
) COMMENT 'Transactional record of each emergency response plan activation at a Sports Entertainment venue or event. Captures activation timestamp, plan activated, activating authority, event reference, incident trigger description, command post location, agencies notified (police, fire, EMS, FBI), evacuation initiated flag, all-clear timestamp, after-action report reference, and casualties/injuries count. SSOT for emergency response execution history.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`security`.`plan_zone_designation` (
    `plan_zone_designation_id` BIGINT COMMENT 'Primary key for the plan_zone_designation association',
    `access_zone_id` BIGINT COMMENT 'Foreign key linking this zone designation record to the specific physical access zone being designated a role within the plan.',
    `emergency_response_plan_id` BIGINT COMMENT 'Foreign key linking this zone designation record to the parent emergency response plan under which the zone role is defined.',
    `activation_sequence_order` STRING COMMENT 'Numeric sequence indicating the order in which this zone is activated or engaged during plan execution. Lower numbers indicate earlier activation. Enables responders to follow a structured zone-by-zone activation protocol during an incident.',
    `effective_date` DATE COMMENT 'Calendar date on which this specific zone designation became operationally active within the plan. Supports versioning of zone role assignments as plans are updated and zones are reconfigured.',
    `evacuation_priority_level` STRING COMMENT 'Numeric priority ranking (1 = highest priority) for evacuating this zone under this specific plan. Priority may differ across plans — a VIP hospitality zone may be priority 1 under an active shooter plan but priority 3 under a severe weather plan.',
    `evacuation_route_description` STRING COMMENT 'Narrative description of primary and secondary evacuation routes for this plan, including ADA-accessible routes, assembly points, and crowd flow management corridors. Aligned with venue floor plan and ADA compliance requirements. [Moved from emergency_response_plan: This STRING field in emergency_response_plan is a denormalized narrative that attempts to capture zone-level evacuation routing. The proper model is to designate specific access_zone records with evacuation_priority_level and zone_role_in_plan in the plan_zone_designation association, replacing this free-text field with structured, queryable zone designations. The narrative description, if needed, can be retained as a notes field on the designation record.]',
    `expiry_date` DATE COMMENT 'Calendar date on which this zone designation expires or is superseded within the plan. Null indicates the designation remains active. Enables historical tracking of which zones served which roles under which plan versions.',
    `shelter_in_place_flag` BOOLEAN COMMENT 'Indicates whether this access zone is designated as a shelter-in-place location under this specific emergency response plan. Belongs to the designation relationship because the same zone may be a shelter-in-place zone under a severe weather plan but an evacuation zone under a fire plan.',
    `triage_zone_flag` BOOLEAN COMMENT 'Indicates whether this access zone is designated as a medical triage area under this specific emergency response plan. A zone may be a triage zone under an MCI plan but not under a fire evacuation plan — hence this flag belongs to the designation, not the zone master record.',
    `zone_role_in_plan` STRING COMMENT 'The specific operational role this access zone is designated to perform under this emergency response plan. A zone may serve as a triage area under one plan and an evacuation staging area under another. This attribute belongs to the designation relationship, not to either the plan or the zone alone.',
    CONSTRAINT pk_plan_zone_designation PRIMARY KEY(`plan_zone_designation_id`)
) COMMENT 'This association product represents the Role-based designation between emergency_response_plan and access_zone. It captures the specific operational role each physical access zone plays within a given emergency response plan — including triage staging, evacuation assembly, shelter-in-place, and command post assignments. Each record links one emergency_response_plan to one access_zone with attributes (zone role, activation sequence, triage/evacuation/shelter flags) that exist only in the context of this plan-zone pairing and cannot be stored on either entity alone.. Existence Justification: In sports venue emergency management, a single emergency response plan explicitly designates multiple access zones for specific operational roles — triage staging, evacuation assembly, shelter-in-place, command post. Conversely, a single access zone (e.g., the field level or a parking compound) can be designated under multiple emergency response plans (active shooter plan, MCI plan, severe weather plan) each assigning it a different role and activation sequence. The business actively manages these designations as a named operational concept called Plan Zone Designation, and the relationship carries its own data (zone role, activation sequence, triage/evacuation flags) that belongs to neither the plan nor the zone alone.';

